'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Info, AlertTriangle } from 'lucide-react'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import toast from 'react-hot-toast'

import { useAuthStore } from '@/stores/auth.store'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Button } from '@/components/ui/button'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { api } from '@/lib/api'

const profileSchema = z.object({
    full_name: z.string().min(2, 'Name must be at least 2 characters'),
    university_id: z.string().optional(),
})

type ProfileForm = z.infer<typeof profileSchema>

interface University {
    id: string
    name: string
    short_code?: string
}

export default function AccountPage() {
    const { user, setUser } = useAuthStore()

    const [universities, setUniversities] = useState<University[]>([])
    const [isLoading, setIsLoading] = useState(false)

    const form = useForm<ProfileForm>({
        resolver: zodResolver(profileSchema),
        defaultValues: {
            full_name: user?.full_name || '',
            university_id: user?.university_id || '',
        },
    })

    useEffect(() => {
        if (user) {
            form.reset({
                full_name: user.full_name,
                university_id: user.university_id || '',
            })
        }
    }, [user, form])

    useEffect(() => {
        const fetchUniversities = async () => {
            try {
                const { data } = await api.get('/universities/')
                setUniversities(data.data || data.results || data || [])
            } catch {
                setUniversities([
                    { id: '1', name: 'American International University-Bangladesh', short_code: 'AIUB' },
                    { id: '2', name: 'University of Dhaka', short_code: 'DU' },
                    { id: '3', name: 'North South University', short_code: 'NSU' },
                    { id: '4', name: 'BRAC University', short_code: 'BRACU' },
                ])
            }
        }
        fetchUniversities()
    }, [])

    const onSubmit = async (data: ProfileForm) => {
        if (!user) return
        setIsLoading(true)
        try {
            const { data: response } = await api.patch('/auth/profile/', data)
            // Update local store with returned user object
            setUser({ ...user, ...response.user })
            toast.success('Profile updated successfully')
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to update profile')
        } finally {
            setIsLoading(false)
        }
    }

    if (!user) return null

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8">
                <h2 className="text-xl font-bold text-gray-900 mb-6">Profile Information</h2>

                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 max-w-xl">
                    <div className="space-y-2">
                        <Label htmlFor="full_name" className="text-xs uppercase tracking-wider text-gray-500 font-semibold">Full Name</Label>
                        <Input
                            id="full_name"
                            {...form.register('full_name')}
                            className="bg-gray-50"
                        />
                        {form.formState.errors.full_name && (
                            <p className="text-xs text-destructive">{form.formState.errors.full_name.message}</p>
                        )}
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="email" className="text-xs uppercase tracking-wider text-gray-500 font-semibold">Email Address</Label>
                        <Input
                            id="email"
                            value={user.email}
                            disabled
                            className="bg-gray-100 text-gray-500 cursor-not-allowed"
                        />
                    </div>

                    <div className="pt-4 border-t border-gray-100">
                        <div className="space-y-2">
                            <Label htmlFor="university_id" className="flex items-center gap-2 text-xs uppercase tracking-wider text-gray-500 font-semibold">
                                Your University / Campus
                                <Info className="h-4 w-4 text-gray-400" />
                            </Label>

                            <Select
                                value={form.watch('university_id')}
                                onValueChange={(val) => form.setValue('university_id', val, { shouldDirty: true })}
                            >
                                <SelectTrigger className="bg-gray-50">
                                    <SelectValue placeholder="Select your university map" />
                                </SelectTrigger>
                                <SelectContent>
                                    {universities.map((uni) => (
                                        <SelectItem key={uni.id} value={uni.id}>
                                            {uni.name} {uni.short_code ? `(${uni.short_code})` : ''}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                            <p className="text-xs text-gray-500 italic">This sets your local feed for the campus marketplace.</p>
                        </div>
                    </div>

                    <Button
                        type="submit"
                        disabled={isLoading || !form.formState.isDirty}
                        className="bg-emerald-600 hover:bg-emerald-700 w-full sm:w-auto px-8"
                    >
                        {isLoading ? 'Saving...' : 'Save Settings'}
                    </Button>
                </form>
            </div>

            {user.role === 'normal_user' && (
                <div className="bg-amber-50 border border-amber-200 rounded-2xl p-6 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="flex items-center gap-4">
                        <div className="bg-amber-100 p-3 rounded-full shrink-0">
                            <AlertTriangle className="h-6 w-6 text-amber-600" />
                        </div>
                        <div>
                            <h3 className="font-bold text-amber-900">Your account is not verified.</h3>
                            <p className="text-sm text-amber-700">Verify to unlock exclusive marketplace features and connect with peers.</p>
                        </div>
                    </div>
                    <Link href="/account/verify" className="shrink-0 w-full sm:w-auto">
                        <Button variant="outline" className="w-full border-amber-300 text-amber-800 hover:bg-amber-100 font-bold shadow-sm">
                            Verify Now &rarr;
                        </Button>
                    </Link>
                </div>
            )}
        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'

import { FileText, Check, Store } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Badge } from '@/components/ui/badge'
import { useToast } from '@/hooks/use-toast'

import { format } from 'date-fns'

type TabType = 'students' | 'ads' | 'sellers'

export default function ApprovalsPage() {
    const { toast } = useToast()
    const [activeTab, setActiveTab] = useState<TabType>('students')

    // MOCK DATA STATES (would normally come from API)
    const [students, setStudents] = useState<any[]>([])
    const [ads, setAds] = useState<any[]>([])
    const [sellers, setSellers] = useState<any[]>([])
    const [isLoading, setIsLoading] = useState(true)

    // Dialog States
    const [rejectReject, setRejectReject] = useState<{ isOpen: boolean, id: string | null, type: TabType | null }>({ isOpen: false, id: null, type: null })
    const [rejectReason, setRejectReason] = useState('')
    const [rejectNotes, setRejectNotes] = useState('')

    const [approveModal, setApproveModal] = useState<{ isOpen: boolean, id: string | null, type: TabType | null, name: string }>({ isOpen: false, id: null, type: null, name: '' })

    useEffect(() => {
        // Mocking API fetch
        setIsLoading(true)
        setTimeout(() => {
            setStudents([
                { id: '1', name: 'Rahim Uddin', uni_code: 'NSU', date: '2024-06-22', image: null, is_pdf: false },
                { id: '2', name: 'Sadia Rahman', uni_code: 'BRACU', date: '2024-06-25', image: 'https://placehold.co/400x250/orange/white?text=ID+Card', is_pdf: false },
            ])
            setAds([
                { id: '101', title: 'Calculus 8th Edition', type: 'Buy', seller: 'Karim', date: '2024-06-26T10:00:00Z', image: 'https://placehold.co/400x250/purple/white?text=Book' }
            ])
            setSellers([
                { id: '201', store_name: 'Tech Gadgets BD', applicant: 'Fahim', uni_code: 'AIUB', date: '2024-06-20' }
            ])
            setIsLoading(false)
        }, 800)
    }, [])

    const handleRejectSubmit = async () => {
        if (!rejectReason) {
            toast({ title: 'Error', description: 'Please select a reason for rejection.', variant: 'destructive' })
            return
        }

        // Mock API call
        // await api.post(`/admin/${rejectReject.type}/${rejectReject.id}/review/`, { action: 'reject', reason: rejectReason, notes: rejectNotes })

        toast({ title: 'Request Rejected', description: `Notification sent to the user.` })

        // Remove locally
        if (rejectReject.type === 'students') setStudents(s => s.filter(x => x.id !== rejectReject.id))
        else if (rejectReject.type === 'ads') setAds(a => a.filter(x => x.id !== rejectReject.id))
        else if (rejectReject.type === 'sellers') setSellers(s => s.filter(x => x.id !== rejectReject.id))

        setRejectReject({ isOpen: false, id: null, type: null })
        setRejectReason('')
        setRejectNotes('')
    }

    const handleApproveSubmit = async () => {
        // Mock API Call
        toast({ title: 'Approved successfully', description: `${approveModal.name} is now active.` })

        if (approveModal.type === 'students') setStudents(s => s.filter(x => x.id !== approveModal.id))
        else if (approveModal.type === 'ads') setAds(a => a.filter(x => x.id !== approveModal.id))
        else if (approveModal.type === 'sellers') setSellers(s => s.filter(x => x.id !== approveModal.id))

        setApproveModal({ isOpen: false, id: null, type: null, name: '' })
    }

    const openReject = (id: string, type: TabType) => setRejectReject({ isOpen: true, id, type })
    const openApprove = (id: string, type: TabType, name: string) => setApproveModal({ isOpen: true, id, type, name })

    return (
        <div className="p-8 max-w-7xl mx-auto min-h-full">

            {/* Header */}
            <div className="mb-8">
                <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">Review Center</h1>
                <p className="text-gray-500 mt-1">Action pending requests across the platform</p>
            </div>

            {/* Tabs */}
            <div className="flex space-x-8 border-b border-gray-200 mb-8">
                {[
                    { id: 'students', label: 'Student Verification', count: students.length },
                    { id: 'ads', label: 'Marketplace Ads', count: ads.length },
                    { id: 'sellers', label: 'Seller Applications', count: sellers.length },
                ].map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as TabType)}
                        className={`pb-4 text-sm font-bold relative transition-colors ${activeTab === tab.id ? 'text-brand-primary' : 'text-gray-500 hover:text-gray-800'
                            }`}
                    >
                        {tab.label}
                        {tab.count > 0 && (
                            <span className="ml-2 inline-flex items-center justify-center bg-gray-100 text-gray-600 text-[10px] px-2 py-0.5 rounded-full font-black">
                                {tab.count}
                            </span>
                        )}
                        {activeTab === tab.id && (
                            <div className="absolute bottom-0 left-0 w-full h-0.5 bg-brand-primary rounded-t-full" />
                        )}
                    </button>
                ))}
            </div>

            {/* Loading State */}
            {isLoading && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-pulse">
                    {[1, 2, 3, 4].map(i => <div key={i} className="h-64 bg-gray-200 rounded-2xl" />)}
                </div>
            )}

            {/* Empty State */}
            {!isLoading && ((activeTab === 'students' && students.length === 0) || (activeTab === 'ads' && ads.length === 0) || (activeTab === 'sellers' && sellers.length === 0)) && (
                <div className="text-center py-20 bg-white rounded-2xl border border-gray-100 border-dashed">
                    <Check className="w-12 h-12 text-green-400 mx-auto mb-3" />
                    <h3 className="text-lg font-bold text-gray-900">All caught up!</h3>
                    <p className="text-sm text-gray-500">There are no pending requests in this queue.</p>
                </div>
            )}

            {/* Tab Contents */}
            {!isLoading && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

                    {/* STUDENTS */}
                    {activeTab === 'students' && students.map((s) => (
                        <div key={s.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden flex flex-col">
                            {/* ID Preview Area */}
                            <div className="aspect-video bg-gray-100 relative group flex items-center justify-center overflow-hidden border-b border-gray-100">
                                {s.is_pdf ? (
                                    <div className="text-center">
                                        <FileText className="w-12 h-12 text-gray-400 mx-auto mb-2" />
                                        <span className="text-xs font-bold text-gray-500">PDF DOCUMENT</span>
                                    </div>
                                ) : s.image ? (
                                    <img src={s.image} alt="ID Card" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                ) : (
                                    <span className="text-sm font-bold text-gray-400 underline cursor-pointer hover:text-gray-600">Click to view ID Card</span>
                                )}
                            </div>

                            {/* Details */}
                            <div className="p-5 flex-1 flex flex-col">
                                <div className="mb-4">
                                    <div className="flex items-center justify-between">
                                        <h3 className="text-lg font-black text-gray-900">{s.name}</h3>
                                        <span className="text-[10px] font-bold tracking-widest text-gray-400 uppercase">REQUESTED: {s.date}</span>
                                    </div>
                                    <p className="text-sm text-gray-500 font-medium">{s.uni_code} University</p>
                                </div>

                                <div className="mt-auto grid grid-cols-2 gap-3 pt-4 border-t border-gray-50">
                                    <Button variant="outline" onClick={() => openReject(s.id, 'students')} className="border-red-200 text-red-600 hover:bg-red-50 hover:text-red-700">Reject</Button>
                                    <Button onClick={() => openApprove(s.id, 'students', s.name)} className="bg-green-600 hover:bg-green-700 text-white">Approve</Button>
                                </div>
                            </div>
                        </div>
                    ))}

                    {/* MARKETPLACE ADS */}
                    {activeTab === 'ads' && ads.map((ad) => (
                        <div key={ad.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden flex flex-col">
                            <div className="aspect-video bg-gray-100 relative group flex items-center justify-center overflow-hidden border-b border-gray-100">
                                {ad.image ? <img src={ad.image} alt="Ad" className="w-full h-full object-cover" /> : <div className="text-gray-400 text-sm font-bold">No Image</div>}
                                <div className="absolute top-3 left-3">
                                    <Badge className="bg-purple-600 text-white border-0 shadow-sm">{ad.type}</Badge>
                                </div>
                            </div>

                            <div className="p-5 flex-1 flex flex-col">
                                <div className="mb-4">
                                    <h3 className="text-lg font-black text-gray-900 line-clamp-1">{ad.title}</h3>
                                    <p className="text-sm text-gray-500">Posted by <span className="font-bold text-gray-700">{ad.seller}</span></p>
                                    <p className="text-xs text-gray-400 mt-1">Submitted on {format(new Date(ad.date), 'MMM dd, yyyy')}</p>
                                </div>
                                <div className="mt-auto grid grid-cols-2 gap-3 pt-4 border-t border-gray-50">
                                    <Button variant="outline" onClick={() => openReject(ad.id, 'ads')} className="border-red-200 text-red-600 hover:bg-red-50 hover:text-red-700">Reject</Button>
                                    <Button onClick={() => openApprove(ad.id, 'ads', ad.title)} className="bg-green-600 hover:bg-green-700 text-white">Approve Listing</Button>
                                </div>
                            </div>
                        </div>
                    ))}

                    {/* SELLERS */}
                    {activeTab === 'sellers' && sellers.map((sel) => (
                        <div key={sel.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 flex flex-col">
                            <div className="mb-4 flex items-start justify-between">
                                <div>
                                    <h3 className="text-xl font-black text-gray-900">{sel.store_name}</h3>
                                    <p className="text-sm text-gray-500 mt-1">Applicant: <span className="font-bold text-gray-800">{sel.applicant}</span> ({sel.uni_code})</p>
                                </div>
                                <Store className="w-8 h-8 text-teal-600 opacity-20" />
                            </div>
                            <p className="text-xs text-gray-400 mb-6">Submitted on {sel.date}</p>

                            <div className="mt-auto grid grid-cols-2 gap-3 pt-4 border-t border-gray-50">
                                <Button variant="outline" onClick={() => openReject(sel.id, 'sellers')} className="border-red-200 text-red-600 hover:bg-red-50 hover:text-red-700">Reject</Button>
                                <Button onClick={() => openApprove(sel.id, 'sellers', sel.store_name)} className="bg-green-600 hover:bg-green-700 text-white">Approve Seller</Button>
                            </div>
                        </div>
                    ))}

                </div>
            )}

            {/* === DIALOGS === */}

            {/* Reject Dialog */}
            <Dialog open={rejectReject.isOpen} onOpenChange={(o) => !o && setRejectReject({ isOpen: false, id: null, type: null })}>
                <DialogContent className="sm:max-w-[425px]">
                    <DialogHeader>
                        <DialogTitle className="text-xl font-black text-gray-900">Reject Request</DialogTitle>
                    </DialogHeader>
                    <div className="grid gap-6 py-4">
                        <div className="space-y-2">
                            <Label className="font-bold">Reason for Rejection</Label>
                            <Select value={rejectReason} onValueChange={setRejectReason}>
                                <SelectTrigger>
                                    <SelectValue placeholder="Select a reason" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="ID not clear">ID not clear</SelectItem>
                                    <SelectItem value="Wrong document">Wrong document type</SelectItem>
                                    <SelectItem value="Expired ID">Expired identification</SelectItem>
                                    <SelectItem value="Name mismatch">Name does not match profile</SelectItem>
                                    <SelectItem value="Policy Violation">Platform policy violation</SelectItem>
                                    <SelectItem value="Other">Other</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label className="font-bold">Additional Notes (Optional)</Label>
                            <Textarea
                                placeholder="Explain specifically what needs to be fixed..."
                                value={rejectNotes}
                                onChange={(e) => setRejectNotes(e.target.value)}
                                className="h-24 resize-none"
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="ghost" onClick={() => setRejectReject({ isOpen: false, id: null, type: null })}>Cancel</Button>
                        <Button onClick={handleRejectSubmit} className="bg-red-600 hover:bg-red-700 text-white">Send Rejection</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Approve Confirmation Dialog */}
            <Dialog open={approveModal.isOpen} onOpenChange={(o) => !o && setApproveModal({ isOpen: false, id: null, type: null, name: '' })}>
                <DialogContent className="sm:max-w-[400px]">
                    <DialogHeader>
                        <DialogTitle className="text-xl font-black text-gray-900 border-b pb-4 mb-2 border-gray-100 flex items-center gap-2">
                            <Check className="w-5 h-5 text-green-500" /> Confirm Approval
                        </DialogTitle>
                    </DialogHeader>
                    <p className="text-gray-600">
                        Are you sure you want to approve <span className="font-bold text-gray-900">{approveModal.name}</span>?
                        {approveModal.type === 'students' && ' This user will gain full access to the marketplace and student privileges.'}
                        {approveModal.type === 'ads' && ' This listing will immediately go live on the public marketplace feed.'}
                        {approveModal.type === 'sellers' && ' This user will instantly be converted into a recognized Seller.'}
                    </p>
                    <DialogFooter className="mt-6">
                        <Button variant="ghost" onClick={() => setApproveModal({ isOpen: false, id: null, type: null, name: '' })}>Cancel</Button>
                        <Button onClick={handleApproveSubmit} className="bg-green-600 hover:bg-green-700 text-white">Confirm Approval</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import { Building2, Plus, Search, MoreHorizontal } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Switch } from '@/components/ui/switch'
import {
    Drawer,
    DrawerContent,
    DrawerHeader,
    DrawerTitle,
    DrawerDescription,
    DrawerFooter,
} from '@/components/ui/drawer'
import { useToast } from '@/hooks/use-toast'
import { api } from '@/lib/api'

interface Campus {
    id: string
    name: string
    short_code: string
    city: string
    is_active: boolean
}

export default function CampusesPage() {
    const { toast } = useToast()
    const [campuses, setCampuses] = useState<Campus[]>([])
    const [searchTerm, setSearchTerm] = useState('')
    const [isLoading, setIsLoading] = useState(true)

    // Drawer State
    const [isDrawerOpen, setIsDrawerOpen] = useState(false)
    const [selectedCampus, setSelectedCampus] = useState<Campus | null>(null)
    const [isAddingNew, setIsAddingNew] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '',
        short_code: '',
        city: '',
        is_active: true
    })

    useEffect(() => {
        setIsLoading(true)
        // Mocking API fetch: api.get('/universities/?include_inactive=true')
        setTimeout(() => {
            const mockData = [
                { id: '1', name: 'American International University-Bangladesh', short_code: 'AIUB', city: 'Dhaka', is_active: true },
                { id: '2', name: 'BRAC University', short_code: 'BRACU', city: 'Dhaka', is_active: true },
                { id: '3', name: 'Daffodil International University', short_code: 'DIU', city: 'Dhaka', is_active: true },
                { id: '4', name: 'North South University', short_code: 'NSU', city: 'Dhaka', is_active: true },
                { id: '5', name: 'Independent University, Bangladesh', short_code: 'IUB', city: 'Dhaka', is_active: false },
                { id: '6', name: 'Bangladesh University of Engineering and Technology', short_code: 'BUET', city: 'Dhaka', is_active: true },
            ]
            setCampuses(mockData)
            setIsLoading(false)
        }, 600)
    }, [])

    const filteredCampuses = campuses.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.short_code.toLowerCase().includes(searchTerm.toLowerCase())
    ).sort((a, b) => a.name.localeCompare(b.name))

    const openEditDrawer = (campus: Campus) => {
        setSelectedCampus(campus)
        setIsAddingNew(false)
        setFormData({
            name: campus.name,
            short_code: campus.short_code,
            city: campus.city,
            is_active: campus.is_active
        })
        setIsDrawerOpen(true)
    }

    const openAddDrawer = () => {
        setSelectedCampus(null)
        setIsAddingNew(true)
        setFormData({ name: '', short_code: '', city: '', is_active: true })
        setIsDrawerOpen(true)
    }

    const handleSave = async () => {
        if (!formData.name || !formData.short_code) {
            toast({ title: 'Validation Error', description: 'Name and short code are required.', variant: 'destructive' })
            return
        }

        try {
            if (isAddingNew) {
                // Mock API POST
                const newCampus = { id: Math.random().toString(), ...formData }
                setCampuses(prev => [...prev, newCampus])
                toast({ title: 'Success', description: 'University added to the network.' })
            } else if (selectedCampus) {
                // Mock API PATCH
                setCampuses(prev => prev.map(c => c.id === selectedCampus.id ? { ...c, ...formData } : c))
                toast({ title: 'Success', description: 'University details updated.' })
            }
            setIsDrawerOpen(false)
        } catch (error) {
            toast({ title: 'Error', description: 'Failed to save university data.', variant: 'destructive' })
        }
    }

    const handleToggleActive = () => {
        setFormData(prev => ({ ...prev, is_active: !prev.is_active }))
    }

    return (
        <div className="p-8 max-w-7xl mx-auto h-full flex flex-col">

            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                <div>
                    <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight flex items-center gap-3">
                        Campus Network
                    </h1>
                    <p className="text-gray-500 mt-1">Managing {campuses.filter(c => c.is_active).length} active universities</p>
                </div>
                <Button onClick={openAddDrawer} className="bg-brand-primary hover:bg-brand-primary-hover text-white shadow-md rounded-xl font-bold h-11 px-6">
                    <Plus className="w-5 h-5 mr-1.5" /> Add University
                </Button>
            </div>

            {/* Search Bar */}
            <div className="relative mb-6">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
                <Input
                    placeholder="Search campuses by name or shorthand..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-11 h-14 bg-white border-gray-200 rounded-2xl text-base shadow-sm focus-visible:ring-brand-primary"
                />
            </div>

            {/* Main Grid */}
            <div className="flex-1 overflow-auto pb-10">
                {isLoading ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-pulse">
                        {[1, 2, 3, 4, 5, 6].map(i => <div key={i} className="h-20 bg-gray-200 rounded-2xl" />)}
                    </div>
                ) : filteredCampuses.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-2xl border border-gray-100 border-dashed">
                        <Building2 className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                        <h3 className="text-lg font-bold text-gray-900">No campuses found</h3>
                        <p className="text-sm text-gray-500">Try adjusting your search query.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {filteredCampuses.map(campus => (
                            <div
                                key={campus.id}
                                onClick={() => openEditDrawer(campus)}
                                className="group bg-white p-5 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md hover:border-brand-primary/30 transition-all cursor-pointer flex items-center justify-between"
                            >
                                <div className="flex items-start gap-4">
                                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-sm shrink-0
                                        ${campus.is_active ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-500'}`}>
                                        {campus.short_code}
                                    </div>
                                    <div>
                                        <h3 className={`font-bold transition-colors group-hover:text-brand-primary ${campus.is_active ? 'text-gray-900' : 'text-gray-400 line-through'}`}>
                                            {campus.name}
                                        </h3>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="text-xs font-semibold text-gray-500">{campus.city}</span>
                                            {!campus.is_active && (
                                                <span className="bg-red-100 text-red-700 text-[9px] px-1.5 py-0.5 rounded font-bold uppercase">Inactive</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                                <div className="text-gray-300 group-hover:text-brand-primary transition-colors">
                                    <MoreHorizontal className="w-5 h-5" />
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* Edit/Add Drawer Sidebar Overlay */}
            <Drawer open={isDrawerOpen} onOpenChange={setIsDrawerOpen} direction="right">
                <DrawerContent className="bg-white flex flex-col rounded-t-[10px] h-full w-[400px] mt-24 fixed bottom-0 right-0">
                    <DrawerHeader className="text-left border-b border-gray-100 pb-4">
                        <DrawerTitle className="font-extrabold text-2xl text-gray-900">
                            {isAddingNew ? 'Add New University' : 'Edit University Node'}
                        </DrawerTitle>
                        <DrawerDescription className="text-gray-500">
                            Modify campus parameters and active status.
                        </DrawerDescription>
                    </DrawerHeader>

                    <div className="p-6 flex-1 overflow-y-auto space-y-6">
                        <div className="space-y-2">
                            <Label htmlFor="uni-name" className="text-gray-700 font-bold">University Full Name</Label>
                            <Input
                                id="uni-name"
                                value={formData.name}
                                onChange={e => setFormData(f => ({ ...f, name: e.target.value }))}
                                placeholder="e.g. American International University"
                                className="bg-gray-50 h-12"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label htmlFor="short-code" className="text-gray-700 font-bold">Short Code</Label>
                                <Input
                                    id="short-code"
                                    value={formData.short_code}
                                    onChange={e => setFormData(f => ({ ...f, short_code: e.target.value.toUpperCase() }))}
                                    placeholder="e.g. AIUB"
                                    className="bg-gray-50 h-10 font-mono tracking-widest text-center"
                                    maxLength={8}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="city" className="text-gray-700 font-bold">Location / City</Label>
                                <Input
                                    id="city"
                                    value={formData.city}
                                    onChange={e => setFormData(f => ({ ...f, city: e.target.value }))}
                                    placeholder="Dhaka"
                                    className="bg-gray-50 h-10"
                                />
                            </div>
                        </div>

                        <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 flex items-center justify-between mt-4">
                            <div>
                                <h4 className="font-bold text-gray-900 mb-0.5">Campus Network Status</h4>
                                <p className="text-xs text-gray-500">
                                    {formData.is_active
                                        ? 'Active. Students can select this campus.'
                                        : 'Inactive. Campus hidden from public dropdowns.'}
                                </p>
                            </div>
                            <Switch checked={formData.is_active} onCheckedChange={handleToggleActive} />
                        </div>
                    </div>

                    <DrawerFooter className="border-t border-gray-100 pt-4 pb-8 flex-row gap-3">
                        <Button variant="outline" className="flex-1 h-12" onClick={() => setIsDrawerOpen(false)}>Cancel</Button>
                        <Button className="flex-1 h-12 bg-brand-primary hover:bg-brand-primary-hover text-white font-bold" onClick={handleSave}>
                            {isAddingNew ? 'Create University' : 'Save Changes'}
                        </Button>
                    </DrawerFooter>
                </DrawerContent>
            </Drawer>

        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import { Tags, Plus, Search, ChevronRight, Folder, Tag, AlertCircle } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Switch } from '@/components/ui/switch'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
    Drawer,
    DrawerContent,
    DrawerHeader,
    DrawerTitle,
    DrawerDescription,
    DrawerFooter,
} from '@/components/ui/drawer'
import { useToast } from '@/hooks/use-toast'
import { api } from '@/lib/api'

interface Category {
    id: string
    name: string
    slug: string
    parent_id: string | null
    is_active: boolean
    children?: Category[]
}

export default function CategoriesPage() {
    const { toast } = useToast()
    const [categories, setCategories] = useState<Category[]>([])
    const [searchTerm, setSearchTerm] = useState('')
    const [isLoading, setIsLoading] = useState(true)

    // Drawer State
    const [isDrawerOpen, setIsDrawerOpen] = useState(false)
    const [selectedCategory, setSelectedCategory] = useState<Category | null>(null)
    const [isAddingNew, setIsAddingNew] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '',
        slug: '',
        parent_id: 'none',
        is_active: true
    })

    useEffect(() => {
        setIsLoading(true)
        // Mocking API fetch: api.get('/categories/tree/?include_inactive=true')
        setTimeout(() => {
            const mockData: Category[] = [
                {
                    id: '1', name: 'Electronics', slug: 'electronics', parent_id: null, is_active: true, children: [
                        { id: '11', name: 'Laptops', slug: 'laptops', parent_id: '1', is_active: true },
                        { id: '12', name: 'Calculators', slug: 'calculators', parent_id: '1', is_active: true },
                    ]
                },
                {
                    id: '2', name: 'Books', slug: 'books', parent_id: null, is_active: true, children: [
                        { id: '21', name: 'Engineering', slug: 'engineering', parent_id: '2', is_active: true },
                        { id: '22', name: 'Business', slug: 'business', parent_id: '2', is_active: false },
                    ]
                },
                { id: '3', name: 'Housing', slug: 'housing', parent_id: null, is_active: true }
            ]
            setCategories(mockData)
            setIsLoading(false)
        }, 700)
    }, [])

    // Flatten tree for dropdown selection
    const flattenCategories = (cats: Category[], prefix = ''): { id: string, name: string }[] => {
        let result: { id: string, name: string }[] = []
        cats.forEach(c => {
            result.push({ id: c.id, name: `${prefix}${c.name}` })
            if (c.children) {
                result = [...result, ...flattenCategories(c.children, `${prefix}${c.name} > `)]
            }
        })
        return result
    }
    const flatList = flattenCategories(categories)

    const openEditDrawer = (category: Category) => {
        setSelectedCategory(category)
        setIsAddingNew(false)
        setFormData({
            name: category.name,
            slug: category.slug,
            parent_id: category.parent_id || 'none',
            is_active: category.is_active
        })
        setIsDrawerOpen(true)
    }

    const openAddDrawer = () => {
        setSelectedCategory(null)
        setIsAddingNew(true)
        setFormData({ name: '', slug: '', parent_id: 'none', is_active: true })
        setIsDrawerOpen(true)
    }

    const handleSave = async () => {
        if (!formData.name || !formData.slug) {
            toast({ title: 'Validation Error', description: 'Name and slug are required.', variant: 'destructive' })
            return
        }

        try {
            // Mocking the save process (reload logic usually hands this off to server)
            toast({ title: 'Success', description: `Category ${isAddingNew ? 'created' : 'updated'}.` })
            setIsDrawerOpen(false)
        } catch (error) {
            toast({ title: 'Error', description: 'Failed to modify category.', variant: 'destructive' })
        }
    }

    // Auto-generate slug from name
    const handleNameChange = (val: string) => {
        const generatedSlug = val.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '')
        setFormData(prev => ({ ...prev, name: val, slug: generatedSlug }))
    }

    // Recursive component to render tree nodes deeply
    const CategoryNode = ({ node, depth = 0 }: { node: Category, depth?: number }) => {

        // Skip rendering if searching and doesn't match
        const matchesSearch = node.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            node.slug.toLowerCase().includes(searchTerm.toLowerCase())

        // If searching, we want to show matched nodes regardless of depth. 
        // If it doesn't match but child does, we still show the parent as a container.
        const childMatches = node.children?.some(c =>
            c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.slug.toLowerCase().includes(searchTerm.toLowerCase())
        )

        if (searchTerm && !matchesSearch && !childMatches) {
            return null
        }

        return (
            <div className="flex flex-col">
                <div
                    onClick={() => openEditDrawer(node)}
                    className={`group flex items-center justify-between p-4 bg-white border-b border-gray-100 hover:bg-gray-50 transition-colors cursor-pointer
                        ${depth === 0 ? 'border-t' : ''}`}
                    style={{ paddingLeft: `${(depth * 32) + 16}px` }}
                >
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${depth === 0 ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-500'}`}>
                            {depth === 0 ? <Folder className="w-4 h-4" /> : <Tag className="w-4 h-4" />}
                        </div>
                        <div>
                            <div className="flex items-center gap-2">
                                <span className={`font-bold ${node.is_active ? 'text-gray-900' : 'text-gray-400 line-through'}`}>
                                    {node.name}
                                </span>
                                {!node.is_active && (
                                    <span className="bg-red-100 text-red-700 text-[9px] px-1.5 py-0.5 rounded font-bold uppercase">Inactive</span>
                                )}
                            </div>
                            <span className="text-xs font-mono text-gray-400">/{node.slug}</span>
                        </div>
                    </div>

                    <div className="text-gray-300 group-hover:text-brand-primary transition-transform group-hover:translate-x-1">
                        <ChevronRight className="w-5 h-5" />
                    </div>
                </div>

                {/* Render children if any */}
                {node.children && node.children.length > 0 && (
                    <div className="flex flex-col border-l-2 border-gray-50 ml-6">
                        {node.children.map(child => (
                            <CategoryNode key={child.id} node={child} depth={depth + 1} />
                        ))}
                    </div>
                )}
            </div>
        )
    }

    return (
        <div className="p-8 max-w-7xl mx-auto h-full flex flex-col">

            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                <div>
                    <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight flex items-center gap-3">
                        Taxonomy Manager
                    </h1>
                    <p className="text-gray-500 mt-1">Manage global categories for Mall and Marketplace logic.</p>
                </div>
                <Button onClick={openAddDrawer} className="bg-brand-primary hover:bg-brand-primary-hover text-white shadow-md rounded-xl font-bold h-11 px-6">
                    <Plus className="w-5 h-5 mr-1.5" /> Add Category
                </Button>
            </div>

            {/* Search Bar */}
            <div className="relative mb-6">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
                <Input
                    placeholder="Search taxonomy nodes..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-11 h-14 bg-white border-gray-200 rounded-2xl text-base shadow-sm focus-visible:ring-brand-primary"
                />
            </div>

            {/* Main Tree List */}
            <div className="flex-1 overflow-auto bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden mb-10">
                {isLoading ? (
                    <div className="flex flex-col animate-pulse">
                        {[1, 2, 3, 4, 5].map(i => <div key={i} className="h-16 border-b border-gray-100 bg-gray-50/50" />)}
                    </div>
                ) : categories.length === 0 ? (
                    <div className="text-center py-20 bg-gray-50 h-full flex flex-col items-center justify-center">
                        <Tags className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                        <h3 className="text-lg font-bold text-gray-900">No categories mapped</h3>
                        <p className="text-sm text-gray-500">Create a root category to get started.</p>
                    </div>
                ) : (
                    <div className="flex flex-col">
                        <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex items-center">
                            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Taxonomy Tree Hierarchy</span>
                        </div>
                        {categories.map(rootNode => (
                            <CategoryNode key={rootNode.id} node={rootNode} />
                        ))}
                    </div>
                )}
            </div>

            {/* Edit/Add Drawer Sidebar Overlay */}
            <Drawer open={isDrawerOpen} onOpenChange={setIsDrawerOpen} direction="right">
                <DrawerContent className="bg-white flex flex-col rounded-t-[10px] h-full w-[400px] mt-24 fixed bottom-0 right-0">
                    <DrawerHeader className="text-left border-b border-gray-100 pb-4">
                        <DrawerTitle className="font-extrabold text-2xl text-gray-900">
                            {isAddingNew ? 'Create Sub-category' : 'Edit Taxonomy Node'}
                        </DrawerTitle>
                        <DrawerDescription className="text-gray-500">
                            Updates propagate to Mall and Marketplace sorting immediately.
                        </DrawerDescription>
                    </DrawerHeader>

                    <div className="p-6 flex-1 overflow-y-auto space-y-6">

                        <div className="space-y-2">
                            <Label className="text-gray-700 font-bold">Category Name</Label>
                            <Input
                                value={formData.name}
                                onChange={e => handleNameChange(e.target.value)}
                                placeholder="e.g. Smart Watches"
                                className="bg-gray-50 h-12"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label className="text-gray-700 font-bold">URL Slug</Label>
                            <Input
                                value={formData.slug}
                                onChange={e => setFormData(f => ({ ...f, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') }))}
                                className="bg-gray-50 h-10 font-mono text-sm text-gray-500"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label className="text-gray-700 font-bold">Parent Category</Label>
                            <Select
                                value={formData.parent_id}
                                onValueChange={(v) => setFormData(f => ({ ...f, parent_id: v }))}
                            >
                                <SelectTrigger className="bg-gray-50 h-12">
                                    <SelectValue placeholder="Select Parent" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="none" className="font-bold text-purple-700">-- ROOT CATEGORY --</SelectItem>
                                    {flatList.map(c => {
                                        // Prevent self-nesting
                                        if (!isAddingNew && selectedCategory && c.id === selectedCategory.id) return null
                                        return (
                                            <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                        )
                                    })}
                                </SelectContent>
                            </Select>
                            <p className="text-[10px] text-gray-500">Setting as ROOT implies top-level navigation.</p>
                        </div>

                        <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 flex items-center gap-4 mt-6">
                            <div className="p-2 bg-yellow-100 rounded-full shrink-0">
                                <AlertCircle className="w-5 h-5 text-yellow-700" />
                            </div>
                            <div className="flex-1">
                                <h4 className="font-bold text-sm text-gray-900 mb-0.5">Visibility Status</h4>
                                <p className="text-xs text-gray-500 leading-tight">
                                    {formData.is_active
                                        ? 'Visible in public catalogues.'
                                        : 'Hidden. Existing items remain accessible via direct link.'}
                                </p>
                            </div>
                            <Switch checked={formData.is_active} onCheckedChange={(c) => setFormData(f => ({ ...f, is_active: c }))} />
                        </div>
                    </div>

                    <DrawerFooter className="border-t border-gray-100 pt-4 pb-8 flex-row gap-3 shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.1)]">
                        <Button variant="outline" className="flex-1 h-12" onClick={() => setIsDrawerOpen(false)}>Cancel</Button>
                        <Button className="flex-1 h-12 bg-brand-primary hover:bg-brand-primary-hover text-white font-bold" onClick={handleSave}>
                            {isAddingNew ? 'Create Node' : 'Save Node'}
                        </Button>
                    </DrawerFooter>
                </DrawerContent>
            </Drawer>

        </div>
    )
}

'use client'

import React, { useEffect, useState } from 'react'
import { DollarSign, Users, Store, Grid, ShoppingBag, ArrowRight } from 'lucide-react'
import Link from 'next/link'
import { api } from '@/lib/api'

export default function AdminDashboardPage() {

    // Fallback static stat structures, will mutate async
    const [stats, setStats] = useState({
        total_revenue: 0,
        total_sellers: 0,
        mall_products: 0,
        marketplace_ads: 0,
        total_orders: 0
    })

    const [quickStats, setQuickStats] = useState({
        buy_listings: 0,
        rental_listings: 0,
        service_listings: 0,
        delivered_orders: 0,
        pending_orders: 0
    })

    const [loading, setLoading] = useState(true)

    useEffect(() => {
        // Mocking the aggregate dashboard API loads
        const fetchStats = async () => {
            try {
                // api.get('/admin/dashboard/stats/')
                // API isn't built yet, so we mock the demo values from S4 instructions
                setTimeout(() => {
                    setStats({
                        total_revenue: 4300.00,
                        total_sellers: 5,
                        mall_products: 16,
                        marketplace_ads: 10,
                        total_orders: 2
                    })

                    setQuickStats({
                        buy_listings: 4,
                        rental_listings: 2,
                        service_listings: 2,
                        delivered_orders: 1,
                        pending_orders: 0
                    })
                    setLoading(false)
                }, 800)
            } catch (err) {
                console.error("Failed to load dashboard stats", err)
                setLoading(false)
            }
        }
        fetchStats()
    }, [])

    const statCards = [
        {
            label: 'TOTAL REVENUE',
            value: `৳${stats.total_revenue.toFixed(2)}`,
            icon: <DollarSign className="w-6 h-6 text-green-600" />,
            color: 'bg-green-100',
            link: '/admin/orders' // Revenue usually derived from orders/mall
        },
        {
            label: 'TOTAL SELLERS',
            value: stats.total_sellers,
            icon: <Users className="w-6 h-6 text-blue-600" />,
            color: 'bg-blue-100',
            link: '/admin/users?role=seller'
        },
        {
            label: 'MALL PRODUCTS',
            value: stats.mall_products,
            icon: <Store className="w-6 h-6 text-teal-600" />,
            color: 'bg-teal-100',
            link: '/admin/mall-products'
        },
        {
            label: 'MARKETPLACE LISTINGS',
            value: stats.marketplace_ads,
            icon: <Grid className="w-6 h-6 text-purple-600" />,
            color: 'bg-purple-100',
            link: '/admin/marketplace'
        },
        {
            label: 'TOTAL ORDERS',
            value: stats.total_orders,
            icon: <ShoppingBag className="w-6 h-6 text-red-600" />,
            color: 'bg-red-100',
            link: '/admin/orders'
        }
    ]

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">

            {/* Page Header */}
            <div>
                <h1 className="text-3xl font-extrabold tracking-tight text-gray-900">Platform Overview</h1>
                <p className="text-gray-500 mt-1">Monitor the pulse of CampusHat.</p>
            </div>

            {/* Stat Cards Grid (Top 4 + bottom 1, per spec) */}
            <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {statCards.slice(0, 4).map((card, idx) => (
                        <div
                            key={idx}
                            className={`bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col relative overflow-hidden ${loading ? 'animate-pulse' : ''}`}
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className={`p-3 rounded-xl ${card.color}`}>
                                    {card.icon}
                                </div>
                            </div>

                            <div className="mt-auto">
                                <h3 className="text-[10px] font-bold text-gray-400 tracking-widest mb-1">{card.label}</h3>
                                <div className="text-3xl font-black text-gray-900">
                                    {loading ? <div className="h-8 w-16 bg-gray-200 rounded mt-1"></div> : card.value}
                                </div>
                            </div>

                            <div className="mt-4 pt-4 border-t border-gray-100">
                                <Link
                                    href={card.link}
                                    className="inline-flex items-center text-xs font-bold text-brand-primary hover:text-brand-primary-hover group"
                                >
                                    INSIGHT
                                    <ArrowRight className="w-3 h-3 ml-1 transform group-hover:translate-x-1 transition-transform" />
                                </Link>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Second Row for overflow stats */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {statCards.slice(4).map((card, idx) => (
                        <div
                            key={`overflow-${idx}`}
                            className={`bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col relative overflow-hidden ${loading ? 'animate-pulse' : ''}`}
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className={`p-3 rounded-xl ${card.color}`}>
                                    {card.icon}
                                </div>
                            </div>

                            <div className="mt-auto">
                                <h3 className="text-[10px] font-bold text-gray-400 tracking-widest mb-1">{card.label}</h3>
                                <div className="text-3xl font-black text-gray-900">
                                    {loading ? <div className="h-8 w-16 bg-gray-200 rounded mt-1"></div> : card.value}
                                </div>
                            </div>

                            <div className="mt-4 pt-4 border-t border-gray-100">
                                <Link
                                    href={card.link}
                                    className="inline-flex items-center text-xs font-bold text-brand-primary hover:text-brand-primary-hover group"
                                >
                                    INSIGHT
                                    <ArrowRight className="w-3 h-3 ml-1 transform group-hover:translate-x-1 transition-transform" />
                                </Link>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Quick Stats Section */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 max-w-md">
                <h2 className="text-lg font-bold text-gray-900 mb-6">Quick Stats</h2>

                <div className="space-y-4">
                    {/* Map quick stats to an array to iterate over dots */}
                    {[
                        { label: 'Buy Listings', val: quickStats.buy_listings },
                        { label: 'Rental Listings', val: quickStats.rental_listings },
                        { label: 'Service Listings', val: quickStats.service_listings },
                        { label: 'Delivered Orders', val: quickStats.delivered_orders },
                        { label: 'Pending Orders', val: quickStats.pending_orders },
                    ].map((stat, i) => (
                        <div key={i} className="flex items-end justify-between text-sm font-medium pb-2 border-b border-gray-50 last:border-0 last:pb-0">
                            <span className="text-gray-600 relative overflow-hidden flex-1 after:content-['......................................................................'] after:absolute after:ml-2 after:text-gray-300">
                                {stat.label}
                            </span>
                            <span className="text-gray-900 font-bold bg-white z-10 pl-2">
                                {loading ? '-' : stat.val}
                            </span>
                        </div>
                    ))}
                </div>
            </div>

        </div>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Eye, EyeOff, Store, Smartphone } from 'lucide-react'
import toast from 'react-hot-toast'

import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardHeader } from '@/components/ui/card'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Separator } from '@/components/ui/separator'
import { api } from '@/lib/api'
import { useAuthStore } from '@/stores/auth.store'

const loginSchema = z.object({
    email: z.string().email('Please enter a valid email'),
    password: z.string().min(6, 'Password must be at least 6 characters'),
})

const otpRequestSchema = z.object({
    identifier: z.string().min(1, 'Email or phone is required'),
})

type LoginForm = z.infer<typeof loginSchema>
type OTPRequestForm = z.infer<typeof otpRequestSchema>

export default function LoginPage() {
    const router = useRouter()
    const { setUser, setAccessToken } = useAuthStore()
    const [showPassword, setShowPassword] = useState(false)
    const [authTab, setAuthTab] = useState<'login' | 'register'>('login')
    const [methodTab, setMethodTab] = useState<'password' | 'otp'>('password')
    const [otpSent, setOtpSent] = useState(false)
    const [otp, setOtp] = useState('')
    const [isLoading, setIsLoading] = useState(false)
    const [emailNotVerified, setEmailNotVerified] = useState(false)
    const [unverifiedEmail, setUnverifiedEmail] = useState('')

    const loginForm = useForm<LoginForm>({
        resolver: zodResolver(loginSchema),
        defaultValues: { email: '', password: '' },
    })

    const otpForm = useForm<OTPRequestForm>({
        resolver: zodResolver(otpRequestSchema),
        defaultValues: { identifier: '' },
    })

    const handlePasswordLogin = async (data: LoginForm) => {
        setIsLoading(true)
        setEmailNotVerified(false)
        try {
            const response = await api.post('/auth/login/', data)
            const { user, access_token } = response.data.data || response.data
            setAccessToken(access_token)
            setUser(user)
            toast.success('Welcome back!')

            // Role-based redirect
            if (user.role === 'admin') {
                router.push('/admin/dashboard')
            } else if (user.role === 'seller') {
                router.push('/seller/dashboard')
            } else {
                router.push('/')
            }
        } catch (error: any) {
            const message = error.response?.data?.message || error.response?.data?.detail || 'Login failed'
            if (message.includes('not verified') || error.response?.data?.code === 'EMAIL_NOT_VERIFIED') {
                setEmailNotVerified(true)
                setUnverifiedEmail(data.email)
            }
            toast.error(message)
        } finally {
            setIsLoading(false)
        }
    }

    const handleSendOtp = async (data: OTPRequestForm) => {
        setIsLoading(true)
        try {
            await api.post('/auth/otp/send/', { identifier: data.identifier })
            setOtpSent(true)
            toast.success('OTP sent! Check your inbox.')
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to send OTP')
        } finally {
            setIsLoading(false)
        }
    }

    const handleVerifyOtp = async () => {
        setIsLoading(true)
        try {
            const response = await api.post('/auth/otp/verify/', {
                identifier: otpForm.getValues('identifier'),
                otp,
            })
            const { user, access_token } = response.data.data || response.data
            setAccessToken(access_token)
            setUser(user)
            toast.success('Welcome!')
            router.push('/')
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Invalid OTP')
        } finally {
            setIsLoading(false)
        }
    }

    const handleResendVerification = async () => {
        try {
            await api.post('/auth/resend-verification/', { email: unverifiedEmail })
            toast.success('Verification email sent!')
        } catch {
            toast.error('Failed to resend verification')
        }
    }

    return (
        <div className="min-h-screen flex bg-surface-base">
            <div className="flex-1 flex flex-col justify-center py-12 px-4 sm:px-6 lg:flex-none lg:w-1/2 lg:px-20 xl:px-24">
                <div className="mx-auto w-full max-w-sm lg:max-w-md">
                    <div className="mb-10 text-center lg:text-left">
                        <div className="flex items-center justify-center lg:justify-start mb-4">
                            <span className="text-3xl font-bold text-gray-800">Campus</span>
                            <span className="text-3xl font-bold text-brand-primary">Hat</span>
                        </div>
                        <h2 className="text-2xl font-bold text-gray-900 leading-tight">Welcome back</h2>
                        <p className="text-sm text-gray-500 mt-2">
                            Enter your credentials to access your account.
                        </p>
                    </div>

                    <div className="bg-white py-8 px-4 shadow-xl sm:rounded-2xl sm:px-10 border border-gray-100 animate-fade-in">
                        {/* Email Not Verified Banner */}
                        {emailNotVerified && (
                            <div className="mb-4 p-3 rounded-btn bg-badge-pending/10 border border-badge-pending text-sm">
                                <p className="font-medium text-badge-pending">Email not verified</p>
                                <p className="text-muted-foreground mt-1">
                                    Please verify your email address.{' '}
                                    <button
                                        onClick={handleResendVerification}
                                        className="text-brand-primary hover:underline font-medium"
                                    >
                                        Resend verification
                                    </button>
                                </p>
                            </div>
                        )}

                        {/* Login / Register Tabs */}
                        <Tabs value={authTab} onValueChange={(v) => setAuthTab(v as 'login' | 'register')}>
                            <TabsList className="w-full">
                                <TabsTrigger value="login" className="flex-1">Login</TabsTrigger>
                                <TabsTrigger value="register" className="flex-1" asChild>
                                    <Link href="/auth/register">Register</Link>
                                </TabsTrigger>
                            </TabsList>

                            <TabsContent value="login" className="mt-6">
                                {/* Password / OTP sub-tabs */}
                                <Tabs value={methodTab} onValueChange={(v) => setMethodTab(v as 'password' | 'otp')}>
                                    <TabsList className="w-full mb-4">
                                        <TabsTrigger value="password" className="flex-1 gap-1.5">
                                            <Eye className="h-3.5 w-3.5" /> Password
                                        </TabsTrigger>
                                        <TabsTrigger value="otp" className="flex-1 gap-1.5">
                                            <Smartphone className="h-3.5 w-3.5" /> OTP
                                        </TabsTrigger>
                                    </TabsList>

                                    {/* Password Login */}
                                    <TabsContent value="password">
                                        <form onSubmit={loginForm.handleSubmit(handlePasswordLogin)} className="space-y-4">
                                            <div className="space-y-2">
                                                <Label htmlFor="email">Email</Label>
                                                <Input
                                                    id="email"
                                                    type="email"
                                                    placeholder="your@university.edu"
                                                    {...loginForm.register('email')}
                                                />
                                                {loginForm.formState.errors.email && (
                                                    <p className="text-xs text-destructive">{loginForm.formState.errors.email.message}</p>
                                                )}
                                            </div>
                                            <div className="space-y-2">
                                                <Label htmlFor="password">Password</Label>
                                                <div className="relative">
                                                    <Input
                                                        id="password"
                                                        type={showPassword ? 'text' : 'password'}
                                                        placeholder="••••••••"
                                                        {...loginForm.register('password')}
                                                    />
                                                    <button
                                                        type="button"
                                                        onClick={() => setShowPassword(!showPassword)}
                                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                                                    >
                                                        {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                                    </button>
                                                </div>
                                                {loginForm.formState.errors.password && (
                                                    <p className="text-xs text-destructive">{loginForm.formState.errors.password.message}</p>
                                                )}
                                            </div>
                                            <Button type="submit" className="w-full" disabled={isLoading}>
                                                {isLoading ? 'Signing in...' : 'Sign In'}
                                            </Button>
                                        </form>
                                    </TabsContent>

                                    {/* OTP Login */}
                                    <TabsContent value="otp">
                                        {!otpSent ? (
                                            <form onSubmit={otpForm.handleSubmit(handleSendOtp)} className="space-y-4">
                                                <div className="space-y-2">
                                                    <Label htmlFor="identifier">Email or Phone</Label>
                                                    <Input
                                                        id="identifier"
                                                        placeholder="Email or phone number"
                                                        {...otpForm.register('identifier')}
                                                    />
                                                    {otpForm.formState.errors.identifier && (
                                                        <p className="text-xs text-destructive">{otpForm.formState.errors.identifier.message}</p>
                                                    )}
                                                </div>
                                                <Button type="submit" className="w-full" disabled={isLoading}>
                                                    {isLoading ? 'Sending...' : 'Send OTP'}
                                                </Button>
                                            </form>
                                        ) : (
                                            <div className="space-y-4">
                                                <div className="space-y-2">
                                                    <Label>Enter 6-digit OTP</Label>
                                                    <Input
                                                        value={otp}
                                                        onChange={(e) => setOtp(e.target.value)}
                                                        placeholder="000000"
                                                        maxLength={6}
                                                        className="text-center text-lg tracking-[0.5em]"
                                                    />
                                                </div>
                                                <Button onClick={handleVerifyOtp} className="w-full" disabled={isLoading}>
                                                    {isLoading ? 'Verifying...' : 'Verify OTP'}
                                                </Button>
                                                <button
                                                    onClick={() => setOtpSent(false)}
                                                    className="text-sm text-brand-primary hover:underline w-full text-center"
                                                >
                                                    Resend OTP
                                                </button>
                                            </div>
                                        )}
                                    </TabsContent>
                                </Tabs>

                                {/* Join as Seller */}
                                <div className="mt-4">
                                    <Button variant="outline" className="w-full gap-2" asChild>
                                        <Link href="/auth/register?seller=true">
                                            <Store className="h-4 w-4" /> Join as Seller
                                        </Link>
                                    </Button>
                                </div>

                                {/* Social Login */}
                                <div className="mt-6">
                                    <div className="relative">
                                        <Separator />
                                        <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-surface-card px-2 text-xs text-muted-foreground">
                                            or continue with
                                        </span>
                                    </div>
                                    <div className="flex justify-center gap-4 mt-4">
                                        {['Google', 'Apple', 'Facebook'].map((provider) => (
                                            <Button key={provider} variant="outline" size="icon" className="rounded-full">
                                                <span className="text-xs font-semibold">{provider[0]}</span>
                                            </Button>
                                        ))}
                                    </div>
                                </div>
                            </TabsContent>
                        </Tabs>
                    </div>
                </div>
            </div>

            <div className="hidden lg:flex flex-1 relative bg-gradient-to-br from-[#634C9F] to-[#45357A] items-center justify-center p-12 overflow-hidden">
                {/* Decorative background elements */}
                <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0">
                    <div className="absolute -top-[20%] -right-[10%] w-[70%] h-[70%] rounded-full bg-white/5 blur-[120px]"></div>
                    <div className="absolute -bottom-[20%] -left-[10%] w-[60%] h-[60%] rounded-full bg-[#8b76c4]/20 blur-[100px]"></div>
                </div>

                <div className="relative z-10 max-w-lg text-white">
                    <div className="bg-white/10 backdrop-blur-md border border-white/20 p-8 rounded-3xl shadow-2xl">
                        <div className="bg-white/20 w-12 h-12 rounded-xl flex items-center justify-center mb-6">
                            <Store className="text-white h-6 w-6" />
                        </div>
                        <h3 className="text-3xl font-bold mb-4">Start your campus journey today</h3>
                        <p className="text-white/80 text-lg leading-relaxed mb-8">
                            Join thousands of students and faculty members buying, selling, and connecting on the ultimate campus marketplace.
                        </p>

                        <div className="flex items-center gap-4">
                            <div className="flex -space-x-4">
                                {[1, 2, 3, 4].map((i) => (
                                    <div key={i} className="w-10 h-10 rounded-full border-2 border-[#45357A] bg-gray-200 overflow-hidden">
                                        <img src={`https://i.pravatar.cc/100?img=${i + 10}`} alt="User" />
                                    </div>
                                ))}
                            </div>
                            <div className="text-sm font-medium">
                                <span className="font-bold">4.9/5</span> rating from 10k+ users
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'
export const dynamic = 'force-dynamic'

import React, { useState, useEffect, useRef, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import Image from 'next/image'
import Link from 'next/link'
import { Search, Send, Image as ImageIcon, CheckCircle, XCircle, ArrowLeft, ArrowRight, CornerDownRight, MessageCircle } from 'lucide-react'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { useAuthStore } from '@/stores/auth.store'
import { api } from '@/lib/api'
import { formatDistanceToNow, format } from 'date-fns'
import { UpgradePrompt } from '@/components/marketplace/UpgradePrompt'

interface ChatParticipant {
    id: number | string
    first_name: string
    last_name: string
    avatar?: string
}

interface ChatListing {
    id: number | string
    title: string
    image: string
    price: string
}

interface ChatThread {
    id: string
    participant: ChatParticipant
    listing: ChatListing
    last_message: string
    last_message_time: string
    unread_count: number
}

interface ChatMessage {
    id: string
    sender_id: number | string
    text: string
    timestamp: string
    is_offer?: boolean
    offer_amount?: string
    offer_status?: 'pending' | 'accepted' | 'declined'
    image?: string
}

function ChatContent() {
    const router = useRouter()
    const searchParams = useSearchParams()
    const urlListingId = searchParams?.get('listing')
    const urlUserId = searchParams?.get('user')

    const { isAuthenticated, user, isVerifiedStudent, isAdmin, isModerator, isSeller } = useAuthStore()
    const canAccessMarketplace = isAuthenticated && (isVerifiedStudent() || isAdmin() || isModerator() || isSeller())

    const [threads, setThreads] = useState<ChatThread[]>([])
    const [activeThreadId, setActiveThreadId] = useState<string | null>(null)
    const [messages, setMessages] = useState<ChatMessage[]>([])
    const [newMessage, setNewMessage] = useState('')
    const [searchQuery, setSearchQuery] = useState('')
    const [loading, setLoading] = useState(true)

    const messagesEndRef = useRef<HTMLDivElement>(null)

    // Load Threads
    useEffect(() => {
        if (!canAccessMarketplace) return

        // Mocking Data for Demonstration
        const mockThreads: ChatThread[] = [
            {
                id: 'chat-1',
                participant: { id: 2, first_name: 'John', last_name: 'Doe', avatar: 'https://placehold.co/100x100' },
                listing: { id: 101, title: 'MacBook Pro M1 2020', image: 'https://placehold.co/100x100', price: '90000' },
                last_message: 'Is this still available?',
                last_message_time: new Date(Date.now() - 3600000).toISOString(),
                unread_count: 2
            },
            {
                id: 'chat-2',
                participant: { id: 3, first_name: 'Sarah', last_name: 'Smith' },
                listing: { id: 102, title: 'Calculus Textbook 8th Ed', image: 'https://placehold.co/100x100', price: '500' },
                last_message: 'I can meet you by the library.',
                last_message_time: new Date(Date.now() - 86400000).toISOString(),
                unread_count: 0
            }
        ]

        setThreads(mockThreads)
        setLoading(false)

        // Automatically create/open active thread if params passed
        if (urlListingId && urlUserId) {
            // Check if thread exists
            const existing = mockThreads.find(t => t.listing.id == urlListingId && t.participant.id == urlUserId)
            if (existing) {
                setActiveThreadId(existing.id)
            } else {
                // Mock creating new thread
                const newThread: ChatThread = {
                    id: `chat-${Date.now()}`,
                    participant: { id: urlUserId, first_name: 'Seller', last_name: 'Account' },
                    listing: { id: urlListingId, title: 'New Conversation', image: 'https://placehold.co/100x100', price: '0' },
                    last_message: 'Start a conversation...',
                    last_message_time: new Date().toISOString(),
                    unread_count: 0
                }
                setThreads(prev => [newThread, ...prev])
                setActiveThreadId(newThread.id)
            }
        } else if (mockThreads.length > 0 && !activeThreadId) {
            // Auto open first on desktop
            if (window.innerWidth >= 768) {
                setActiveThreadId(mockThreads[0].id)
            }
        }
    }, [canAccessMarketplace, urlListingId, urlUserId, activeThreadId])

    // Load Messages
    useEffect(() => {
        if (!activeThreadId) return

        // Mock Messages Payload
        setMessages([
            { id: 'm1', sender_id: 2, text: 'Hi, is this still available?', timestamp: new Date(Date.now() - 7200000).toISOString() },
            { id: 'm2', sender_id: user?.id || 1, text: 'Yes it is! Are you on campus today?', timestamp: new Date(Date.now() - 7000000).toISOString() },
            { id: 'm3', sender_id: 2, text: 'I made an offer.', timestamp: new Date(Date.now() - 3600000).toISOString(), is_offer: true, offer_amount: '85000', offer_status: 'pending' },
        ])

        // Setup Dummy WebSocket
        // const ws = new WebSocket(`ws://localhost:8000/api/ws/chat/${activeThreadId}/`)
        // ws.onmessage = (e) => { const newMsg = JSON.parse(e.data); setMessages(prev => [...prev, newMsg]) }
        // return () => ws.close()
    }, [activeThreadId, user?.id])

    // Auto scroll bottom
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, [messages])

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!newMessage.trim() || !activeThreadId) return

        const msgPayload: ChatMessage = {
            id: `temp-${Date.now()}`,
            sender_id: user?.id || 1,
            text: newMessage.trim(),
            timestamp: new Date().toISOString()
        }

        // Optimistic UI
        setMessages(prev => [...prev, msgPayload])
        setThreads(prev => prev.map(t => t.id === activeThreadId ? { ...t, last_message: msgPayload.text, last_message_time: msgPayload.timestamp } : t))
        setNewMessage('')

        try {
            await api.post(`/marketplace/chats/${activeThreadId}/messages/`, { text: msgPayload.text })
        } catch (error) {
            console.error("Message send failed through API. (Expected on Frontend Demo)")
        }
    }

    const respondToOffer = async (msgId: string, accept: boolean) => {
        // Toggle locally
        setMessages(prev => prev.map(m => m.id === msgId ? { ...m, offer_status: accept ? 'accepted' : 'declined' } : m))
        // API Call
        try {
            await api.patch(`/marketplace/chats/offers/${msgId}/`, { status: accept ? 'accepted' : 'declined' })
        } catch (error) {
            console.error("Failed to update offer status")
        }
    }

    if (!canAccessMarketplace) {
        return (
            <div className="min-h-screen bg-[#F5F5F5] pt-12">
                <UpgradePrompt
                    isOpen={true}
                    onClose={() => router.push('/marketplace')}
                    title="Verification Required"
                    description="You must verify your university email to use the chat system. This stops spam and keeps our community safe."
                />
            </div>
        )
    }

    const activeThread = threads.find(t => t.id === activeThreadId)
    const filteredThreads = threads.filter(t =>
        t.participant.first_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        t.listing.title.toLowerCase().includes(searchQuery.toLowerCase())
    )

    return (
        <div className="bg-[#F5F5F5] min-h-[calc(100vh-64px)] h-full">
            <div className="container mx-auto max-w-7xl h-[calc(100vh-64px)] p-0 md:p-4">
                <div className="bg-white md:rounded-2xl border-x md:border border-gray-100 shadow-sm overflow-hidden flex h-full">

                    {/* LEFT PANEL: Chat List */}
                    <div className={`w-full md:w-[350px] lg:w-[400px] flex-shrink-0 border-r border-gray-100 flex flex-col ${activeThreadId ? 'hidden md:flex' : 'flex'}`}>
                        <div className="p-4 border-b border-gray-100 bg-gray-50/50">
                            <h2 className="text-xl font-extrabold text-[#1A1A2E] mb-4">Messages</h2>
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                                <Input
                                    placeholder="Search chats..."
                                    className="pl-9 h-10 border-gray-200 focus-visible:ring-brand-primary"
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto overflow-x-hidden">
                            {filteredThreads.map(thread => (
                                <div
                                    key={thread.id}
                                    onClick={() => setActiveThreadId(thread.id)}
                                    className={`flex items-start gap-3 p-4 border-b border-gray-50 cursor-pointer transition-colors ${activeThreadId === thread.id ? 'bg-brand-primary/5 border-l-4 border-l-brand-primary' : 'hover:bg-gray-50 border-l-4 border-l-transparent'}`}
                                >
                                    <div className="relative">
                                        <div className="w-12 h-12 rounded-full overflow-hidden bg-gray-100 border border-gray-200">
                                            {thread.participant.avatar ? (
                                                <Image src={thread.participant.avatar} alt="Avatar" width={48} height={48} className="object-cover w-full h-full" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center bg-brand-primary text-white font-bold text-lg">
                                                    {thread.participant.first_name[0]}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex justify-between items-baseline mb-0.5">
                                            <h4 className="font-bold text-gray-900 truncate pr-2">{thread.participant.first_name} {thread.participant.last_name}</h4>
                                            <span className="text-[10px] text-gray-500 shrink-0">{formatDistanceToNow(new Date(thread.last_message_time))}</span>
                                        </div>
                                        <p className="text-[11px] font-semibold text-brand-primary truncate">{thread.listing.title}</p>
                                        <div className="flex justify-between items-center mt-1">
                                            <p className={`text-xs truncate max-w-[200px] ${thread.unread_count > 0 ? 'text-gray-900 font-bold' : 'text-gray-500'}`}>
                                                {thread.last_message}
                                            </p>
                                            {thread.unread_count > 0 && (
                                                <div className="w-5 h-5 rounded-full bg-brand-primary text-white text-[10px] font-bold flex items-center justify-center shrink-0 shadow-sm">
                                                    {thread.unread_count}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                            {filteredThreads.length === 0 && (
                                <div className="p-8 text-center text-gray-500 text-sm">No messages found.</div>
                            )}
                        </div>
                    </div>

                    {/* RIGHT PANEL: Active Chat Window */}
                    <div className={`flex-1 flex flex-col bg-[#FDFDFD] relative ${!activeThreadId ? 'hidden md:flex items-center justify-center' : 'flex'}`}>
                        {!activeThreadId ? (
                            <div className="text-center text-gray-400">
                                <MessageCircle className="w-16 h-16 mx-auto mb-4 opacity-20" />
                                <h3 className="text-lg font-bold text-gray-900">Your Messages</h3>
                                <p className="text-sm">Select a conversation from the sidebar to start chatting.</p>
                            </div>
                        ) : activeThread ? (
                            <>
                                {/* Chat Header */}
                                <div className="h-16 md:h-20 border-b border-gray-100 bg-white flex items-center px-4 justify-between shrink-0 shadow-sm z-10">
                                    <div className="flex items-center gap-3 w-full">
                                        <button onClick={() => setActiveThreadId(null)} className="md:hidden w-8 h-8 flex items-center justify-center text-gray-500 hover:text-gray-900">
                                            <ArrowLeft className="w-5 h-5" />
                                        </button>
                                        <Link href={`/marketplace/listings/${activeThread.listing.id}`} className="flex items-center gap-3 hover:bg-gray-50 p-1.5 rounded-xl transition-colors min-w-0">
                                            <div className="w-10 h-10 md:w-12 md:h-12 rounded-lg overflow-hidden bg-gray-100 hidden sm:block shrink-0">
                                                <Image src={activeThread.listing.image} alt={activeThread.listing.title} width={48} height={48} className="object-cover w-full h-full" />
                                            </div>
                                            <div className="min-w-0 pr-4">
                                                <h3 className="font-bold text-gray-900 leading-none mb-1">
                                                    {activeThread.participant.first_name} {activeThread.participant.last_name}
                                                </h3>
                                                <p className="text-xs text-gray-500 truncate flex items-center gap-1 font-medium">
                                                    <CornerDownRight className="w-3 h-3 text-brand-primary" />
                                                    {activeThread.listing.title} <span className="font-bold text-gray-900 ml-1">৳{activeThread.listing.price}</span>
                                                </p>
                                            </div>
                                        </Link>
                                    </div>
                                </div>

                                {/* Messages Area */}
                                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                                    <div className="text-center my-4">
                                        <span className="bg-gray-100 text-gray-500 text-[10px] uppercase font-bold px-3 py-1 rounded-full">
                                            Chat Started
                                        </span>
                                    </div>

                                    {messages.map((msg, idx) => {
                                        const isMe = msg.sender_id === (user?.id || 1)
                                        const showAvatar = !isMe && (idx === 0 || messages[idx - 1].sender_id !== msg.sender_id)

                                        if (msg.is_offer) {
                                            return (
                                                <div key={msg.id} className={`flex w-full ${isMe ? 'justify-end' : 'justify-start'}`}>
                                                    <div className={`max-w-[85%] md:max-w-[70%] bg-white border ${isMe ? 'border-brand-primary/20 shadow-md shadow-brand-primary/5' : 'border-gray-200 shadow-sm'} rounded-2xl p-4 relative`}>
                                                        <div className="flex items-center justify-between gap-4 mb-3 border-b border-gray-100 pb-3">
                                                            <div>
                                                                <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">{isMe ? 'You made an Offer' : 'Received an Offer'}</p>
                                                                <p className="text-2xl font-black text-brand-primary tracking-tight">৳{Number(msg.offer_amount).toLocaleString()}</p>
                                                            </div>
                                                            {msg.offer_status === 'pending' && <Badge className="bg-yellow-100 text-yellow-800">Pending</Badge>}
                                                            {msg.offer_status === 'accepted' && <Badge className="bg-green-100 text-green-800">Accepted</Badge>}
                                                            {msg.offer_status === 'declined' && <Badge variant="destructive">Declined</Badge>}
                                                        </div>
                                                        <p className="text-sm text-gray-700 font-medium leading-relaxed mb-4">&quot;{msg.text}&quot;</p>

                                                        {msg.offer_status === 'pending' && !isMe && (
                                                            <div className="flex gap-2">
                                                                <Button onClick={() => respondToOffer(msg.id, true)} className="flex-1 bg-green-50 text-green-700 hover:bg-green-100 border border-green-200 gap-1 h-9">
                                                                    <CheckCircle className="w-4 h-4" /> Accept
                                                                </Button>
                                                                <Button onClick={() => respondToOffer(msg.id, false)} className="flex-1 bg-red-50 text-red-700 hover:bg-red-100 border border-red-200 gap-1 h-9">
                                                                    <XCircle className="w-4 h-4" /> Decline
                                                                </Button>
                                                            </div>
                                                        )}
                                                        {msg.offer_status === 'pending' && isMe && (
                                                            <p className="text-xs text-gray-500 italic text-center">Waiting for seller response...</p>
                                                        )}
                                                        <span className="text-[9px] text-gray-400 absolute bottom-2 right-3 font-medium">
                                                            {format(new Date(msg.timestamp), 'h:mm a')}
                                                        </span>
                                                    </div>
                                                </div>
                                            )
                                        }

                                        return (
                                            <div key={msg.id} className={`flex w-full gap-2 ${isMe ? 'justify-end' : 'justify-start'}`}>
                                                {!isMe && (
                                                    <div className="w-8 shrink-0">
                                                        {showAvatar && (
                                                            <div className="w-8 h-8 rounded-full bg-gray-200 overflow-hidden">
                                                                <Image src={activeThread.participant.avatar || 'https://placehold.co/100x100'} alt="Avatar" width={32} height={32} />
                                                            </div>
                                                        )}
                                                    </div>
                                                )}
                                                <div className="flex flex-col max-w-[75%] md:max-w-[65%]">
                                                    <div className={`p-3 text-[15px] leading-relaxed relative ${isMe ? 'bg-brand-primary text-white rounded-2xl rounded-tr-sm' : 'bg-gray-100 text-gray-900 rounded-2xl rounded-tl-sm'}`}>
                                                        {msg.image && (
                                                            <div className="mb-2 relative w-full h-40 rounded-lg overflow-hidden border border-white/20">
                                                                <Image src={msg.image} alt="Attachment" fill className="object-cover" />
                                                            </div>
                                                        )}
                                                        <p className="break-words">{msg.text}</p>
                                                        <div className={`text-[9px] mt-1 text-right font-medium ${isMe ? 'text-brand-primary-light/70' : 'text-gray-400'}`}>
                                                            {format(new Date(msg.timestamp), 'h:mm a')}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )
                                    })}
                                    <div ref={messagesEndRef} />
                                </div>

                                {/* Input Area */}
                                <div className="p-4 bg-white border-t border-gray-100">
                                    <form onSubmit={handleSendMessage} className="flex gap-2">
                                        <div className="relative flex-1">
                                            <Button type="button" variant="ghost" size="icon" className="absolute left-1 top-1/2 -translate-y-1/2 w-8 h-8 text-gray-400 hover:text-brand-primary hover:bg-brand-primary/10 rounded-full">
                                                <ImageIcon className="w-5 h-5" />
                                            </Button>
                                            <Input
                                                placeholder="Type a message..."
                                                className="pl-10 pr-4 h-12 bg-gray-50 border-gray-200 rounded-full focus-visible:ring-brand-primary"
                                                value={newMessage}
                                                onChange={(e) => setNewMessage(e.target.value)}
                                            />
                                        </div>
                                        <Button
                                            type="submit"
                                            disabled={!newMessage.trim()}
                                            className="h-12 w-12 rounded-full p-0 bg-brand-primary hover:bg-brand-dark text-white shadow-md flex-shrink-0"
                                        >
                                            <Send className="w-5 h-5 ml-1" />
                                        </Button>
                                    </form>
                                </div>
                            </>
                        ) : null}
                    </div>
                </div>
            </div>
        </div>
    )
}

export default function ChatPage() {
    return (
        <Suspense fallback={<div className="min-h-screen bg-[#F5F5F5] pt-20 text-center text-gray-500 animate-pulse">Loading discussion...</div>}>
            <ChatContent />
        </Suspense>
    )
}

'use client'
export const dynamic = 'force-dynamic'

import React, { useState, useEffect, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import Image from 'next/image'
import { ShoppingBag, Key, Briefcase, Utensils, X, Info, Plus, ArrowLeft } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Checkbox } from "@/components/ui/checkbox"
import { useAuthStore } from '@/stores/auth.store'
import { api } from '@/lib/api'
import { useToast } from '@/hooks/use-toast'
import { UpgradePrompt } from '@/components/marketplace/UpgradePrompt'

type PostType = 'buy' | 'rental' | 'service' | 'food'

function PostAdContent() {
    const router = useRouter()
    const searchParams = useSearchParams()
    const editId = searchParams?.get('edit')
    const { toast } = useToast()

    const { isAuthenticated, user, isVerifiedStudent, isAdmin, isModerator, isSeller } = useAuthStore()
    const canAccessMarketplace = isAuthenticated && (isVerifiedStudent() || isAdmin() || isModerator() || isSeller())

    const [isSubmitting, setIsSubmitting] = useState(false)
    const [isLoadingEdit, setIsLoadingEdit] = useState(false)
    const [errors, setErrors] = useState<Record<string, string>>({})

    // Active upload tab (for Section 3)
    const [photoMode, setPhotoMode] = useState<'url' | 'upload'>('url')

    // Form State
    const [adData, setAdData] = useState({
        post_type: 'buy' as PostType,
        title: '',
        description: '',
        category: '',
        condition: '', // Only for buy/rental
        price: '',
        duration_days: '15',
        is_anonymous: false,
        campus_visibility: 'own_university'
    })

    // Image arrays (Up to 8 combined)
    const [imageUrls, setImageUrls] = useState<string[]>([''])
    const [uploadFiles, setUploadFiles] = useState<File[]>([])
    const [uploadPreviews, setUploadPreviews] = useState<string[]>([])
    const [existingImages, setExistingImages] = useState<{ id: number, image: string }[]>([])

    // Categories mapping
    const categoriesMap: Record<PostType, string[]> = {
        buy: ['Textbooks', 'Electronics', 'Furniture', 'Clothing', 'Sports', 'Other'],
        rental: ['Housing', 'Appliances', 'Vehicles', 'Tools', 'Other'],
        service: ['Tutoring', 'Design', 'Labor', 'Tech Support', 'Other'],
        food: ['Homemade Meals', 'Snacks', 'Bakery', 'Other'],
    }

    // Load Edit Data
    useEffect(() => {
        if (editId && canAccessMarketplace) {
            setIsLoadingEdit(true)
            api.get(`/marketplace/listings/${editId}/`)
                .then(res => {
                    const data = res.data
                    setAdData({
                        post_type: data.post_type as PostType,
                        title: data.title,
                        description: data.description,
                        category: data.category?.name || data.category,
                        condition: data.condition || '',
                        price: data.price.toString(),
                        duration_days: '15', // Fallback, normally calculate from expires_at if needed
                        is_anonymous: false, // Default since API might not expose this flag
                        campus_visibility: 'own_university'
                    })
                    setExistingImages(data.images || [])
                    setPhotoMode('upload') // Assume if editing, show the rich preview gallery
                })
                .catch(err => {
                    toast({ title: "Error Loading Ad", description: "Could not fetch existing ad data.", variant: "destructive" })
                })
                .finally(() => setIsLoadingEdit(false))
        }
    }, [editId, canAccessMarketplace])

    // Handlers
    const updateAdData = (field: string, value: any) => {
        setAdData(prev => ({ ...prev, [field]: value }))
        // Clear error for this field
        if (errors[field]) setErrors(prev => ({ ...prev, [field]: undefined } as any))
    }

    const handleTypeChange = (type: PostType) => {
        setAdData(prev => ({
            ...prev,
            post_type: type,
            category: categoriesMap[type][0], // Auto-select first category
            condition: (type === 'buy' || type === 'rental') ? 'USED-GOOD' : '' // Reset or set default condition
        }))
    }

    // Image URL logic
    const handleUrlChange = (index: number, value: string) => {
        const newUrls = [...imageUrls]
        newUrls[index] = value
        setImageUrls(newUrls)
    }
    const addUrlRow = () => {
        const totalImages = imageUrls.filter(u => u.trim() !== '').length + uploadFiles.length + existingImages.length
        if (totalImages < 8) setImageUrls(prev => [...prev, ''])
    }
    const removeUrlRow = (index: number) => {
        setImageUrls(prev => prev.filter((_, i) => i !== index))
        if (imageUrls.length === 1) setImageUrls(['']) // keep at least one empty
    }

    // Image File logic
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!e.target.files) return
        const currentCount = imageUrls.filter(u => u.trim() !== '').length + uploadFiles.length + existingImages.length
        const allowed = 8 - currentCount

        const filesArray = Array.from(e.target.files).slice(0, allowed)
        setUploadFiles(prev => [...prev, ...filesArray])

        const newPreviews = filesArray.map(file => URL.createObjectURL(file))
        setUploadPreviews(prev => [...prev, ...newPreviews])
    }
    const removeUploadFile = (index: number) => {
        URL.revokeObjectURL(uploadPreviews[index])
        setUploadFiles(prev => prev.filter((_, i) => i !== index))
        setUploadPreviews(prev => prev.filter((_, i) => i !== index))
    }
    const removeExistingImage = (index: number) => {
        // Just remove from array visually, backend patch should handle remaining
        setExistingImages(prev => prev.filter((_, i) => i !== index))
    }

    // Submit Validation
    const validateForm = () => {
        const newErrors: Record<string, string> = {}
        if (!adData.title.trim()) newErrors.title = "Title is required"
        else if (adData.title.length < 5) newErrors.title = "Title must be at least 5 characters"

        if (!adData.description.trim()) newErrors.description = "Description is required"
        else if (adData.description.length < 20) newErrors.description = "Description must be at least 20 characters"
        else if (adData.description.length > 1000) newErrors.description = "Description cannot exceed 1000 characters"

        if (!adData.category) newErrors.category = "Category is required"
        if ((adData.post_type === 'buy' || adData.post_type === 'rental') && !adData.condition) {
            newErrors.condition = "Condition is required"
        }

        if (!adData.price && adData.price !== '0') newErrors.price = "Price is required"
        else if (isNaN(Number(adData.price)) || Number(adData.price) < 0) newErrors.price = "Price must be a valid positive number"

        const totalImages = imageUrls.filter(u => u.trim() !== '').length + uploadFiles.length + existingImages.length
        if (totalImages === 0) newErrors.images = "Please add at least one image"

        setErrors(newErrors)
        return Object.keys(newErrors).length === 0
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!validateForm()) {
            // Scroll to top to show banner if needed
            window.scrollTo({ top: 0, behavior: 'smooth' })
            return
        }

        setIsSubmitting(true)
        try {
            const formData = new FormData()
            formData.append('post_type', adData.post_type)
            formData.append('title', adData.title)
            formData.append('description', adData.description)
            formData.append('category', adData.category)

            if (adData.condition) formData.append('condition', adData.condition)
            formData.append('price', adData.price)
            formData.append('duration_days', adData.duration_days)
            formData.append('is_anonymous', String(adData.is_anonymous))
            formData.append('campus_visibility', adData.campus_visibility)

            // Handle URL images vs File uploads based on backend requirements
            // For now, mapping valid URLs back to a comma-separated string if the backend supports it:
            const validUrls = imageUrls.filter(u => u.trim() !== '')
            if (validUrls.length > 0) formData.append('image_urls', JSON.stringify(validUrls))

            // Append binary files
            uploadFiles.forEach(file => formData.append('uploaded_images', file))

            if (editId) {
                // Determine remaining existing image IDs to keep
                const existingImageIds = existingImages.map(img => img.id)
                formData.append('keep_images', JSON.stringify(existingImageIds))
                await api.patch(`/marketplace/listings/${editId}/`, formData, { headers: { 'Content-Type': 'multipart/form-data' } })
                toast({ title: 'Success', description: 'Your ad has been updated and is back Under Review.' })
            } else {
                await api.post('/marketplace/listings/', formData, { headers: { 'Content-Type': 'multipart/form-data' } })
                toast({ title: 'Success', description: "Ad submitted for review. We'll notify you when it's approved." })
            }
            router.push('/marketplace/my-ads')

        } catch (error: any) {
            toast({
                title: "Failed to save ad",
                description: error.response?.data?.detail || "Please check your inputs and try again.",
                variant: "destructive"
            })
        } finally {
            setIsSubmitting(false)
        }
    }

    if (!canAccessMarketplace) {
        return (
            <div className="min-h-[calc(100vh-64px)] bg-[#F5F5F5] pt-12 flex justify-center px-4">
                <UpgradePrompt
                    isOpen={true}
                    onClose={() => router.push('/marketplace')}
                    title="Verification Required"
                    description="You must verify your university email to post ads on the Marketplace. This builds trust and keeps your campus safe."
                />
            </div>
        )
    }

    if (isLoadingEdit) {
        return <div className="min-h-screen pt-20 text-center animate-pulse text-gray-500">Loading ad data...</div>
    }

    const adTypeCards = [
        { id: 'buy', icon: <ShoppingBag className="w-6 h-6" />, label: 'Sell Item' },
        { id: 'rental', icon: <Key className="w-6 h-6" />, label: 'For Rent' },
        { id: 'service', icon: <Briefcase className="w-6 h-6" />, label: 'Service' },
        { id: 'food', icon: <Utensils className="w-6 h-6" />, label: 'Food' },
    ]

    const totalUploadedImages = imageUrls.filter(u => u.trim() !== '').length + uploadFiles.length + existingImages.length

    return (
        <div className="bg-[#F5F5F5] min-h-screen pb-20 pt-8 sm:pt-12">
            <div className="container mx-auto px-4 max-w-2xl">

                {/* Header */}
                <div className="text-center mb-10">
                    <div className="flex items-center justify-center gap-2 mb-2 text-sm text-gray-500 font-medium">
                        <span onClick={() => router.back()} className="cursor-pointer hover:text-brand-primary">Marketplace</span>
                        <span>/</span>
                        <span className="text-gray-900">{editId ? 'Edit Advertisement' : 'Post New Advertisement'}</span>
                    </div>
                    <h1 className="text-3xl md:text-4xl font-extrabold text-[#1A1A2E] tracking-tight mb-2">
                        {editId ? 'Edit Your Ad' : 'What are you offering?'}
                    </h1>
                    <p className="text-gray-500">
                        {editId ? 'Update your listing details below.' : 'Reach fellow students across your campus community in minutes.'}
                    </p>
                </div>

                {Object.keys(errors).length > 0 && (
                    <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl text-red-600 font-medium text-sm">
                        Please correct the errors below before submitting.
                    </div>
                )}

                {/* Main Form Card */}
                <form onSubmit={handleSubmit} className="bg-white rounded-2xl border border-gray-100 shadow-xl overflow-hidden p-6 sm:p-8 space-y-12">

                    {/* SECTION 1: Select Type */}
                    <div className="space-y-6">
                        <h2 className="text-lg font-bold text-gray-900 border-b border-gray-100 pb-2">
                            <span className="text-brand-primary mr-1">1.</span> Select Advertisement Type
                        </h2>

                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                            {adTypeCards.map(type => {
                                const isSelected = adData.post_type === type.id
                                return (
                                    <button
                                        type="button"
                                        key={type.id}
                                        onClick={() => handleTypeChange(type.id as PostType)}
                                        className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all gap-2
                                            ${isSelected
                                                ? 'bg-brand-primary border-brand-primary text-white shadow-md scale-105'
                                                : 'bg-white border-gray-200 text-gray-600 hover:border-gray-300 hover:bg-gray-50 hover:text-gray-900'
                                            }`}
                                    >
                                        <div className={/* Always retain color if not selected, but white if selected? Demo says purple background, white icon. Let's just use current color inheritance */ "inherit"}>
                                            {type.icon}
                                        </div>
                                        <span className="text-xs font-bold uppercase tracking-wider">{type.label}</span>
                                    </button>
                                )
                            })}
                        </div>
                    </div>

                    {/* SECTION 2: About Your Ad */}
                    <div className="space-y-6">
                        <h2 className="text-lg font-bold text-gray-900 border-b border-gray-100 pb-2">
                            <span className="text-brand-primary mr-1">2.</span> About Your Ad
                        </h2>

                        {/* Title */}
                        <div className="space-y-2">
                            <Label htmlFor="title" className="text-gray-700 font-bold">Ad Title</Label>
                            <Input
                                id="title"
                                placeholder="e.g. 2nd Year Mechanical Engineering Books"
                                value={adData.title}
                                onChange={e => updateAdData('title', e.target.value)}
                                className={`h-12 bg-gray-50 border-gray-200 ${errors.title ? 'border-red-500 focus-visible:ring-red-500' : 'focus-visible:ring-brand-primary'}`}
                            />
                            {errors.title && <p className="text-xs text-red-500 font-medium">{errors.title}</p>}
                        </div>

                        {/* Description */}
                        <div className="space-y-2">
                            <Label htmlFor="description" className="text-brand-primary font-bold">Description</Label>
                            <Textarea
                                id="description"
                                placeholder="Tell us more about what you're offering..."
                                rows={4}
                                value={adData.description}
                                onChange={e => updateAdData('description', e.target.value)}
                                className={`resize-none bg-gray-50 border-gray-200 ${errors.description ? 'border-red-500 focus-visible:ring-red-500' : 'focus-visible:ring-brand-primary'}`}
                            />
                            <div className="flex justify-between items-center text-xs">
                                {errors.description ? (
                                    <span className="text-red-500 font-medium">{errors.description}</span>
                                ) : <span />}
                                <span className={`${adData.description.length > 1000 ? 'text-red-500 font-bold' : 'text-gray-400'}`}>
                                    {adData.description.length} / 1000
                                </span>
                            </div>
                        </div>

                        {/* Category & Condition */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <Label className="text-gray-700 font-bold">Category</Label>
                                <Select value={adData.category} onValueChange={val => updateAdData('category', val)}>
                                    <SelectTrigger className={`h-12 bg-gray-50 border-gray-200 ${errors.category && !adData.category ? 'border-red-500' : ''}`}>
                                        <SelectValue placeholder="Select Category" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {(categoriesMap[adData.post_type] || []).map(cat => (
                                            <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                                {errors.category && !adData.category && <p className="text-xs text-red-500 font-medium">{errors.category}</p>}
                            </div>

                            {(adData.post_type === 'buy' || adData.post_type === 'rental') && (
                                <div className="space-y-2">
                                    <Label className="text-gray-700 font-bold">Condition</Label>
                                    <Select value={adData.condition} onValueChange={val => updateAdData('condition', val)}>
                                        <SelectTrigger className={`h-12 bg-gray-50 border-gray-200 ${errors.condition && !adData.condition ? 'border-red-500' : ''}`}>
                                            <SelectValue placeholder="Select Condition" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="NEW">New</SelectItem>
                                            <SelectItem value="USED-LIKE NEW">Used - Like New</SelectItem>
                                            <SelectItem value="USED-GOOD">Used - Good</SelectItem>
                                            <SelectItem value="USED-FAIR">Used - Fair</SelectItem>
                                        </SelectContent>
                                    </Select>
                                    {errors.condition && !adData.condition && <p className="text-xs text-red-500 font-medium">{errors.condition}</p>}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* SECTION 3: Add Photos */}
                    <div className="space-y-6">
                        <div className="border-b border-gray-100 pb-2 mb-4">
                            <h2 className="text-lg font-bold text-gray-900 inline-flex items-center">
                                <span className="text-brand-primary mr-1">3.</span> Add Photos
                            </h2>
                            <p className="text-sm text-gray-500 mt-1">High quality photos help you get more responses. Upload at least one image.</p>
                        </div>

                        {/* Toggle Mode */}
                        <div className="inline-flex bg-gray-100 p-1 rounded-lg">
                            <button type="button" onClick={() => setPhotoMode('url')} className={`px-4 py-1.5 text-sm font-bold rounded-md transition-colors ${photoMode === 'url' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}>Enter URL</button>
                            <button type="button" onClick={() => setPhotoMode('upload')} className={`px-4 py-1.5 text-sm font-bold rounded-md transition-colors ${photoMode === 'upload' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}>Upload File</button>
                        </div>

                        {photoMode === 'url' ? (
                            <div className="space-y-3 bg-gray-50 p-4 border border-gray-100 rounded-xl">
                                {imageUrls.map((url, i) => (
                                    <div key={i} className="flex items-start gap-2">
                                        <div className="flex-1 space-y-1">
                                            {i === 0 && <Label className="text-brand-primary font-bold text-xs uppercase">Main Image URL</Label>}
                                            <Input
                                                placeholder="https://image-hosting.com/my-photo.jpg"
                                                value={url}
                                                onChange={e => handleUrlChange(i, e.target.value)}
                                                className="bg-white"
                                            />
                                        </div>
                                        <div className={i === 0 ? "pt-5" : ""}>
                                            <Button type="button" variant="ghost" size="icon" onClick={() => removeUrlRow(i)} className="text-gray-400 hover:text-red-500 hover:bg-red-50">
                                                <X className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </div>
                                ))}

                                {totalUploadedImages < 8 && (
                                    <button
                                        type="button"
                                        onClick={addUrlRow}
                                        className="text-brand-primary font-bold text-sm hover:underline flex items-center gap-1 mt-2"
                                    >
                                        <Plus className="w-4 h-4" /> Add another photo
                                    </button>
                                )}
                            </div>
                        ) : (
                            <div className="space-y-4">
                                <div className="border-2 border-dashed border-gray-300 rounded-2xl p-8 hover:border-brand-primary hover:bg-brand-primary/5 transition-colors text-center relative flex flex-col items-center justify-center bg-gray-50">
                                    <input type="file" multiple accept="image/jpeg,image/png,image/webp" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={totalUploadedImages >= 8} />
                                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm mb-3 text-brand-primary">
                                        <Plus className="w-6 h-6" />
                                    </div>
                                    <p className="font-bold text-gray-900">Click to upload files</p>
                                    <p className="text-xs text-gray-500 mt-1">JPG/PNG, max 5MB. Up to 8 photos.</p>
                                </div>
                            </div>
                        )}

                        {errors.images && <p className="text-sm font-bold text-red-500 mt-2">{errors.images}</p>}

                        {/* Combined Previews */}
                        {(uploadPreviews.length > 0 || imageUrls.some(u => u.trim() !== '') || existingImages.length > 0) && (
                            <div className="pt-4">
                                <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3">Image Previews</p>
                                <div className="grid grid-cols-4 sm:grid-cols-5 gap-3">
                                    {/* Existing Edit Images */}
                                    {existingImages.map((img, i) => (
                                        <div key={`existing-${img.id}`} className="relative aspect-square rounded-lg border border-gray-200 overflow-hidden group bg-white shadow-sm">
                                            <Image src={img.image} alt="Preview" fill className="object-cover" />
                                            <button type="button" onClick={() => removeExistingImage(i)} className="absolute top-1 right-1 bg-black/60 hover:bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                                                <X className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))}

                                    {/* Valid URLs Previews */}
                                    {imageUrls.map((u, i) => u.trim() !== '' && (
                                        <div key={`url-${i}`} className="relative aspect-square rounded-lg border border-gray-200 overflow-hidden group bg-white shadow-sm">
                                            <img src={u} alt="URL Preview" className="w-full h-full object-cover" onError={(e) => { (e.target as any).src = 'https://placehold.co/200x200?text=Invalid+URL' }} />
                                            <span className="absolute bottom-0 left-0 right-0 bg-black/50 text-white text-[9px] text-center py-0.5">URL</span>
                                        </div>
                                    ))}

                                    {/* File Upload Previews */}
                                    {uploadPreviews.map((src, i) => (
                                        <div key={`upload-${i}`} className="relative aspect-square rounded-lg border border-gray-200 overflow-hidden group bg-white shadow-sm">
                                            <Image src={src} alt="Upload Preview" fill className="object-cover" />
                                            <button type="button" onClick={() => removeUploadFile(i)} className="absolute top-1 right-1 bg-black/60 hover:bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                                                <X className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* SECTION 4: Pricing & Visibility */}
                    <div className="space-y-6">
                        <h2 className="text-lg font-bold text-gray-900 border-b border-gray-100 pb-2">
                            <span className="text-brand-primary mr-1">4.</span> Pricing & Visibility
                        </h2>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                            <div className="space-y-2 relative">
                                <Label htmlFor="price" className="text-gray-700 font-bold">Price <span className="text-gray-400 font-normal">(৳)</span></Label>
                                <div className="relative">
                                    <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 font-bold">৳</span>
                                    <Input
                                        type="number"
                                        id="price"
                                        placeholder="0.00"
                                        value={adData.price}
                                        onChange={e => updateAdData('price', e.target.value)}
                                        className={`pl-8 h-12 bg-gray-50 border-gray-200 ${errors.price ? 'border-red-500 focus-visible:ring-red-500' : 'focus-visible:ring-brand-primary'}`}
                                    />
                                </div>
                                <p className="text-[11px] text-gray-500 font-medium">
                                    {adData.post_type === 'service' ? 'Rate per session/hour' : adData.post_type === 'food' ? 'Price per portion/set' : 'Total price for the item.'}
                                </p>
                                {errors.price && <p className="text-xs text-red-500 font-medium">{errors.price}</p>}
                            </div>

                            <div className="space-y-2">
                                <Label className="text-gray-700 font-bold">Listing Duration</Label>
                                <Select value={adData.duration_days} onValueChange={val => updateAdData('duration_days', val)}>
                                    <SelectTrigger className="h-12 bg-gray-50 border-gray-200">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="7">7 Days</SelectItem>
                                        <SelectItem value="15">15 Days</SelectItem>
                                        <SelectItem value="30">30 Days</SelectItem>
                                    </SelectContent>
                                </Select>
                                <p className="text-[11px] text-gray-500 font-medium">Your ad will automatically expire after this period.</p>
                            </div>
                        </div>

                        <div className="flex flex-row items-start space-x-3 space-y-0 rounded-xl border border-gray-200 p-4 shadow-sm bg-gray-50/50">
                            <Checkbox
                                id="anonymous"
                                checked={adData.is_anonymous}
                                onCheckedChange={(c: boolean | 'indeterminate') => updateAdData('is_anonymous', c === true)}
                                className="mt-1"
                            />
                            <div className="space-y-1 leading-none">
                                <Label htmlFor="anonymous" className="font-bold text-gray-900 cursor-pointer">Post Anonymously</Label>
                                <p className="text-xs text-gray-500">
                                    Hide your profile name and avatar from this listing. Your verified status badge will still be shown to build trust.
                                </p>
                            </div>
                        </div>

                        {/* Campus Detection Banner */}
                        <div className="bg-blue-50 p-4 text-blue-800 rounded-xl flex items-start gap-3 border border-blue-100">
                            <Info className="w-5 h-5 mt-0.5 shrink-0 text-blue-600" />
                            <div>
                                <p className="font-bold text-sm text-blue-900 mb-1">Automatic Campus Detection</p>
                                <p className="text-xs leading-relaxed">
                                    This ad will be listed for <span className="font-bold bg-blue-100 px-1 py-0.5 rounded">{user?.university_name || 'All Universities'}</span>.
                                    Only verified users from your campus will see this in their local feed.
                                </p>
                            </div>

                        </div>
                    </div>
                </form>

                {/* Footer Controls */}
                <div className="mt-6 flex justify-between items-center px-2 py-4">
                    <button
                        type="button"
                        onClick={() => router.back()}
                        className="text-brand-primary font-bold hover:underline flex items-center gap-1"
                        disabled={isSubmitting}
                    >
                        <ArrowLeft className="w-4 h-4" /> Cancel
                    </button>

                    <Button
                        onClick={handleSubmit}
                        disabled={isSubmitting}
                        className="bg-[#059669] hover:bg-green-700 text-white shadow-xl h-12 px-8 font-bold text-base tracking-wide"
                    >
                        {isSubmitting ? 'Processing...' : editId ? 'Save Changes' : 'Submit for Review'}
                    </Button>
                </div>

            </div>
        </div>
    )
}

export default function PostAdPage() {
    return (
        <Suspense fallback={<div className="min-h-screen pt-20 text-center animate-pulse text-gray-500">Loading form...</div>}>
            <PostAdContent />
        </Suspense>
    )
}

'use client'

import { useState, useEffect } from 'react'
import Image from 'next/image'
import Link from 'next/link'
import { useParams, useRouter } from 'next/navigation'
import {
    Heart,
    Minus,
    Plus,
    Share2,
    ShieldCheck,
    Truck,
    RotateCcw,
    ChevronRight,
    Home,
    MessageSquare,
    Store as StoreIcon
} from 'lucide-react'
import { toast } from 'react-hot-toast'

import { api } from '@/lib/api'
import { useCartStore } from '@/stores/cart.store'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { StarRating } from '@/components/shared/StarRating'
import { CurrencyDisplay } from '@/components/shared/CurrencyDisplay'
import { cn } from '@/lib/utils'

// Types based on expected API
interface Variant {
    id: string
    sku: string
    price: string
    stock_quantity: number
    attributes: Record<string, string> // e.g. { "Color": "Red", "Size": "M" }
}

interface ProductDetail {
    id: string
    slug: string
    name: string
    description: string
    base_price: string
    discount_price?: string | null
    stock_quantity: number
    has_variants: boolean
    variants: Variant[]
    category: {
        id: string
        name: string
        slug: string
    }
    seller: {
        id: string
        store_name: string
        slug: string
        rating: number
        followers_count: number
    }
    images: { id: string, image_url: string, is_primary: boolean }[]
    rating_avg: number
    rating_count: number
    tags: string[]
}

export default function ProductDetailPage() {
    const { slug } = useParams()
    const router = useRouter()
    const { addItem } = useCartStore()

    const [product, setProduct] = useState<ProductDetail | null>(null)
    const [isLoading, setIsLoading] = useState(true)

    // Interactive State
    const [activeImage, setActiveImage] = useState<string>('')
    const [quantity, setQuantity] = useState(1)
    const [selectedAttributes, setSelectedAttributes] = useState<Record<string, string>>({})
    const [activeVariant, setActiveVariant] = useState<Variant | null>(null)
    const [isWishlisted, setIsWishlisted] = useState(false)

    // Derived Variants UI Mappings (extracting available Colors, Sizes, etc.)
    const availableAttributes = product?.variants?.reduce((acc, v) => {
        Object.entries(v.attributes).forEach(([key, val]) => {
            if (!acc[key]) acc[key] = new Set()
            acc[key].add(val)
        })
        return acc
    }, {} as Record<string, Set<string>>)

    // Fetch Details
    useEffect(() => {
        const fetchProduct = async () => {
            setIsLoading(true)
            try {
                // If API is down, provide a high fidelity mock matching the data structure
                const { data } = await api.get(`/mall/products/${slug}/`).catch(() => ({
                    data: {
                        id: `prod-${slug}`,
                        slug: slug as string,
                        name: 'Premium Wireless Over-Ear Headphones',
                        description: `
                            <p>Experience studio-quality sound with our premium wireless headphones. Designed specifically for long study sessions, featuring ultra-soft ear cushions and active noise cancellation (ANC).</p>
                            <ul>
                                <li>Up to 40 hours battery life</li>
                                <li>Bluetooth 5.2 multi-point connection</li>
                                <li>Built-in microphone for clear calls</li>
                            </ul>
                        `,
                        base_price: '2500.00',
                        discount_price: '1990.00',
                        stock_quantity: 45,
                        has_variants: true,
                        variants: [
                            { id: 'v1', sku: 'HP-BLK', price: '1990.00', stock_quantity: 20, attributes: { 'Color': 'Midnight Black' } },
                            { id: 'v2', sku: 'HP-SLV', price: '2100.00', stock_quantity: 15, attributes: { 'Color': 'Lunar Silver' } },
                            { id: 'v3', sku: 'HP-BLU', price: '1990.00', stock_quantity: 10, attributes: { 'Color': 'Navy Blue' } },
                        ],
                        category: { id: 'c1', name: 'Electronics', slug: 'electronics' },
                        seller: { id: 's1', store_name: 'TechHub AU', slug: 'techhub', rating: 4.8, followers_count: 1250 },
                        images: [
                            { id: 'img1', image_url: '/img-placeholder.jpg', is_primary: true },
                            { id: 'img2', image_url: '/img-placeholder-2.jpg', is_primary: false },
                            { id: 'img3', image_url: '/img-placeholder-3.jpg', is_primary: false },
                        ],
                        rating_avg: 4.6,
                        rating_count: 128,
                        tags: ['gadgets', 'audio', 'study-essential']
                    }
                }))

                setProduct(data)

                // Set initial image
                const primary = data.images?.find((img: any) => img.is_primary)?.image_url
                setActiveImage(primary || data.images?.[0]?.image_url || '')

                // Auto-select first variant if exists
                if (data.has_variants && data.variants && data.variants.length > 0) {
                    setSelectedAttributes(data.variants[0].attributes)
                    setActiveVariant(data.variants[0])
                }

            } finally {
                setIsLoading(false)
            }
        }
        fetchProduct()
    }, [slug])

    // Update active variant when selections change
    useEffect(() => {
        if (!product || !product.has_variants) return

        const matched = product.variants.find(v => {
            return Object.entries(selectedAttributes).every(([k, val]) => v.attributes[k] === val)
        })

        if (matched) {
            setActiveVariant(matched)
            setQuantity(1) // Reset quantity on variant change
        } else {
            setActiveVariant(null)
        }
    }, [selectedAttributes, product])

    const handleAttributeSelect = (key: string, value: string) => {
        setSelectedAttributes(prev => ({ ...prev, [key]: value }))
    }

    const handleAddToCart = () => {
        if (!product) return

        let finalPrice = product.discount_price || product.base_price
        let variantId = undefined
        let variantInfo = undefined

        if (product.has_variants) {
            if (!activeVariant) {
                toast.error('Please select all options before adding to cart.')
                return
            }
            if (activeVariant.stock_quantity < quantity) {
                toast.error('Not enough stock available for this variation.')
                return
            }
            finalPrice = activeVariant.price
            variantId = activeVariant.id
            variantInfo = activeVariant.attributes
        } else {
            if (product.stock_quantity < quantity) {
                toast.error('Not enough stock available.')
                return
            }
        }

        addItem({
            id: crypto.randomUUID(),
            product_id: product.id,
            name: product.name,
            slug: product.slug,
            price: finalPrice,
            image_url: activeImage,
            quantity: quantity,
            variant_id: variantId,
            variant_info: variantInfo
        })

        toast.success(`Added ${quantity} ${quantity > 1 ? 'items' : 'item'} to your cart`)
    }

    if (isLoading) {
        return <div className="min-h-screen bg-surface-base animate-pulse py-12 px-4 flex justify-center"><div className="w-full max-w-6xl h-[600px] bg-white rounded-2xl"></div></div>
    }

    if (!product) {
        return <div className="text-center py-20 text-gray-500">Product not found.</div>
    }

    // Calculations
    const currentPrice = product.has_variants
        ? (activeVariant ? activeVariant.price : product.base_price)
        : (product.discount_price || product.base_price)

    const originalPrice = product.has_variants ? null : product.base_price

    // Safety boundaries for Stock
    const maxStock = product.has_variants ? (activeVariant?.stock_quantity || 0) : product.stock_quantity
    const isOutOfStock = maxStock === 0

    return (
        <div className="min-h-screen bg-[#F5F5F5] pb-20 pt-6">
            <div className="container mx-auto px-4 max-w-6xl">

                {/* BREADCRUMB */}
                <nav className="flex items-center text-sm text-gray-500 mb-6 gap-2">
                    <Link href="/" className="hover:text-brand-primary transition-colors flex items-center">
                        <Home className="h-4 w-4" />
                    </Link>
                    <ChevronRight className="h-4 w-4" />
                    <Link href={`/mall/category/${product.category.slug}`} className="hover:text-brand-primary transition-colors">
                        {product.category.name}
                    </Link>
                    <ChevronRight className="h-4 w-4" />
                    <span className="text-gray-900 font-medium truncate max-w-[200px] sm:max-w-none">{product.name}</span>
                </nav>

                {/* MAIN GRID */}
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 bg-white rounded-3xl p-4 sm:p-8 shadow-sm border border-gray-100 mb-10">

                    {/* LEFT: Image Gallery */}
                    <div className="lg:col-span-5 flex flex-col gap-4 relative">
                        {/* Status Badges Overlaid */}
                        <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
                            {isOutOfStock && <Badge variant="secondary" className="bg-gray-900 text-white font-bold">Out of Stock</Badge>}
                            {(!isOutOfStock && maxStock < 10) && <Badge className="bg-orange-500 hover:bg-orange-600 text-white">Only {maxStock} left!</Badge>}
                        </div>

                        {/* Main Image */}
                        <div className="aspect-square w-full rounded-2xl overflow-hidden bg-gray-50 border border-gray-100 flex items-center justify-center relative group">
                            {activeImage ? (
                                <Image
                                    src={activeImage}
                                    alt={product.name}
                                    fill
                                    className="object-cover"
                                    unoptimized
                                />
                            ) : (
                                <span className="text-6xl text-gray-200">{product.name.charAt(0)}</span>
                            )}
                        </div>

                        {/* Thumbnails */}
                        {product.images.length > 1 && (
                            <div className="flex gap-3 overflow-x-auto pb-2 hide-scrollbar">
                                {product.images.map((img) => (
                                    <button
                                        key={img.id}
                                        onClick={() => setActiveImage(img.image_url)}
                                        className={cn(
                                            "h-20 w-20 shrink-0 rounded-xl overflow-hidden border-2 transition-all",
                                            activeImage === img.image_url ? "border-brand-primary shadow-md" : "border-transparent opacity-60 hover:opacity-100"
                                        )}
                                    >
                                        <div className="w-full h-full relative bg-gray-50">
                                            <Image src={img.image_url} alt="Thumbnail" fill className="object-cover" unoptimized />
                                        </div>
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* RIGHT: Product Info */}
                    <div className="lg:col-span-7 flex flex-col">

                        {/* Title & Ratings */}
                        <div className="mb-6">
                            <h1 className="text-2xl sm:text-3xl font-black text-gray-900 leading-tight mb-3">
                                {product.name}
                            </h1>
                            <div className="flex flex-wrap items-center gap-4 text-sm">
                                <span className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded-md text-gray-600 font-medium">
                                    <StarRating rating={product.rating_avg} count={0} /> {product.rating_avg}
                                </span>
                                <a href="#reviews" className="text-brand-primary hover:underline font-medium">
                                    {product.rating_count} Reviews
                                </a>
                                <span className="text-gray-300">|</span>
                                <span className="text-gray-500 flex items-center gap-1">
                                    <StoreIcon className="h-4 w-4" />
                                    Sold by: <Link href={`/sellers/${product.seller.slug}`} className="text-brand-primary hover:underline font-bold">{product.seller.store_name}</Link>
                                </span>
                            </div>
                        </div>

                        <hr className="border-gray-100 mb-6" />

                        {/* Pricing */}
                        <div className="mb-8">
                            <div className="flex items-end gap-3 mb-2">
                                <CurrencyDisplay amount={parseFloat(currentPrice)} className="text-4xl font-black text-gray-900" />
                                {originalPrice && parseFloat(originalPrice) > parseFloat(currentPrice) && (
                                    <CurrencyDisplay amount={parseFloat(originalPrice)} className="text-xl text-gray-400 line-through font-medium mb-1" />
                                )}
                            </div>

                            {originalPrice && parseFloat(originalPrice) > parseFloat(currentPrice) && (
                                <div className="inline-flex bg-red-50 text-red-600 px-3 py-1 rounded-full text-xs font-bold tracking-wide">
                                    SAVE ৳{parseFloat(originalPrice) - parseFloat(currentPrice)} ({Math.round(((parseFloat(originalPrice) - parseFloat(currentPrice)) / parseFloat(originalPrice)) * 100)}%)
                                </div>
                            )}
                        </div>

                        {/* Variants Selector */}
                        {product.has_variants && availableAttributes && (
                            <div className="space-y-6 mb-8 bg-gray-50 p-5 rounded-2xl border border-gray-100">
                                {Object.entries(availableAttributes).map(([attrName, attrValues]) => (
                                    <div key={attrName}>
                                        <h3 className="text-sm font-bold text-gray-900 mb-3">{attrName}: <span className="font-normal text-brand-primary">{selectedAttributes[attrName]}</span></h3>
                                        <div className="flex flex-wrap gap-3">
                                            {Array.from(attrValues).map(val => {
                                                const isSelected = selectedAttributes[attrName] === val
                                                return (
                                                    <button
                                                        key={val}
                                                        onClick={() => handleAttributeSelect(attrName, val)}
                                                        className={cn(
                                                            "px-4 py-2 border rounded-xl text-sm font-medium transition-all",
                                                            isSelected
                                                                ? "border-brand-primary bg-brand-light/20 text-brand-primary shadow-sm"
                                                                : "border-gray-200 bg-white text-gray-700 hover:border-gray-300 hover:bg-gray-50",
                                                        )}
                                                    >
                                                        {val}
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Quantity & Actions Row */}
                        <div className="flex flex-col sm:flex-row gap-4 mb-8">
                            <div className="flex items-center bg-gray-50 border border-gray-200 rounded-xl h-14 p-1 w-full sm:w-32 shrink-0">
                                <button
                                    className="flex-1 h-full flex items-center justify-center text-gray-500 hover:text-gray-900 hover:bg-white rounded-lg transition-colors disabled:opacity-30 disabled:hover:bg-transparent"
                                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                                    disabled={quantity <= 1 || isOutOfStock}
                                >
                                    <Minus className="h-5 w-5" />
                                </button>
                                <div className="w-10 text-center font-bold text-gray-900 select-none">
                                    {quantity}
                                </div>
                                <button
                                    className="flex-1 h-full flex items-center justify-center text-gray-500 hover:text-gray-900 hover:bg-white rounded-lg transition-colors disabled:opacity-30 disabled:hover:bg-transparent"
                                    onClick={() => setQuantity(q => Math.min(maxStock, q + 1))}
                                    disabled={quantity >= maxStock || isOutOfStock}
                                >
                                    <Plus className="h-5 w-5" />
                                </button>
                            </div>

                            <Button
                                className="flex-1 h-14 text-lg font-bold bg-[#1A1A2E] hover:bg-[#2A2A4E] text-white shadow-md active:scale-[0.98] transition-all"
                                onClick={handleAddToCart}
                                disabled={isOutOfStock || (product.has_variants && !activeVariant)}
                            >
                                {isOutOfStock ? 'Sold Out' : 'Add to Cart'}
                            </Button>

                            <Button
                                variant="outline"
                                size="icon"
                                className={cn("h-14 w-14 shrink-0 rounded-xl border-gray-200 hover:bg-red-50 hover:text-red-500 transition-colors", isWishlisted && "text-red-500 bg-red-50 border-red-100")}
                                onClick={() => setIsWishlisted(!isWishlisted)}
                            >
                                <Heart className="h-6 w-6" fill={isWishlisted ? 'currentColor' : 'none'} />
                            </Button>
                        </div>

                        {/* Trust Badges */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-8">
                            <div className="flex items-center gap-3 bg-gray-50 p-3 rounded-xl">
                                <ShieldCheck className="h-6 w-6 text-emerald-500 shrink-0" />
                                <div className="text-xs">
                                    <p className="font-bold text-gray-900">Verified Seller</p>
                                    <p className="text-gray-500">Student/Faculty authenticated</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 bg-gray-50 p-3 rounded-xl">
                                <Truck className="h-6 w-6 text-blue-500 shrink-0" />
                                <div className="text-xs">
                                    <p className="font-bold text-gray-900">On-Campus Delivery</p>
                                    <p className="text-gray-500">Fast local exchange</p>
                                </div>
                            </div>
                        </div>

                        {/* Short Note/Tags */}
                        <div className="mt-auto">
                            <div className="flex gap-2 flex-wrap">
                                {product.tags.map(tag => (
                                    <span key={tag} className="text-xs font-semibold bg-gray-100 text-gray-600 px-3 py-1 rounded-full">#{tag}</span>
                                ))}
                            </div>
                        </div>

                    </div>
                </div>

                {/* BOTTOM TABBED SECTION */}
                <div id="details" className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 sm:p-8">
                    <Tabs defaultValue="description" className="w-full">
                        <TabsList className="w-full justify-start h-auto p-0 bg-transparent border-b border-gray-200 rounded-none mb-8 overflow-x-auto">
                            <TabsTrigger
                                value="description"
                                className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-brand-primary data-[state=active]:shadow-none rounded-none text-base font-bold text-gray-500 data-[state=active]:text-brand-primary px-6 pb-4"
                            >
                                Description
                            </TabsTrigger>
                            <TabsTrigger
                                value="reviews"
                                className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-brand-primary data-[state=active]:shadow-none rounded-none text-base font-bold text-gray-500 data-[state=active]:text-brand-primary px-6 pb-4"
                            >
                                Reviews ({product.rating_count})
                            </TabsTrigger>
                            <TabsTrigger
                                value="shipping"
                                className="data-[state=active]:bg-transparent data-[state=active]:border-b-2 data-[state=active]:border-brand-primary data-[state=active]:shadow-none rounded-none text-base font-bold text-gray-500 data-[state=active]:text-brand-primary px-6 pb-4"
                            >
                                Shipping & Returns
                            </TabsTrigger>
                        </TabsList>

                        <TabsContent value="description" className="focus:outline-none">
                            <div className="prose prose-gray max-w-none prose-p:leading-relaxed prose-headings:font-bold prose-a:text-brand-primary prose-ul:list-disc prose-ul:ml-4"
                                dangerouslySetInnerHTML={{ __html: product.description }}
                            />
                        </TabsContent>

                        <TabsContent value="reviews" id="reviews" className="focus:outline-none">
                            <div className="flex flex-col md:flex-row gap-12">
                                {/* Summary block */}
                                <div className="md:w-1/3 shrink-0">
                                    <h3 className="text-xl font-bold mb-4">Customer Reviews</h3>
                                    <div className="flex items-center gap-4 mb-6">
                                        <div className="text-5xl font-black text-gray-900">{product.rating_avg.toFixed(1)}</div>
                                        <div>
                                            <StarRating rating={product.rating_avg} count={0} />
                                            <div className="text-sm text-gray-500 mt-1">Based on {product.rating_count} reviews</div>
                                        </div>
                                    </div>
                                    <Button variant="outline" className="w-full font-bold">Write a Review</Button>
                                    <p className="text-xs text-center text-gray-400 mt-3">Only verified buyers can review</p>
                                </div>
                                {/* Feed block */}
                                <div className="md:w-2/3 space-y-6">
                                    <div className="bg-gray-50 p-6 rounded-2xl flex flex-col items-center justify-center text-center">
                                        <MessageSquare className="h-10 w-10 text-gray-300 mb-3" />
                                        <p className="font-semibold text-gray-700">Detailed reviews component pending mapping.</p>
                                    </div>
                                </div>
                            </div>
                        </TabsContent>

                        <TabsContent value="shipping" className="focus:outline-none">
                            <div className="grid sm:grid-cols-2 gap-8">
                                <div>
                                    <h3 className="font-bold flex items-center gap-2 mb-3"><Truck className="h-5 w-5 text-gray-400" /> Delivery Options</h3>
                                    <ul className="space-y-3 text-sm text-gray-600">
                                        <li className="flex justify-between border-b pb-2"><span>On-Campus Meetup</span> <span className="font-bold text-emerald-600">Free</span></li>
                                        <li className="flex justify-between border-b pb-2"><span>Standard Delivery (2-3 days)</span> <span className="font-bold">৳60</span></li>
                                    </ul>
                                </div>
                                <div>
                                    <h3 className="font-bold flex items-center gap-2 mb-3"><RotateCcw className="h-5 w-5 text-gray-400" /> Return Policy</h3>
                                    <p className="text-sm text-gray-600 leading-relaxed">
                                        Returns accepted within 3 days of delivery if the item acts contrary to the description. Product must be in identical condition. Contact the seller directly via chat to initiate.
                                    </p>
                                </div>
                            </div>
                        </TabsContent>
                    </Tabs>
                </div>
            </div>
        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import {
    Store, User, Users, CheckCircle2, ChevronRight, UploadCloud, X, Verified, Building2
} from 'lucide-react'
import { useAuthStore } from '@/stores/auth.store'
import { api } from '@/lib/api'
import { toast } from 'react-hot-toast'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Checkbox } from '@/components/ui/checkbox'

type BusinessType = 'individual' | 'student_seller' | 'club' | 'business' | 'official_store'

export default function SellerApplyPage() {
    const router = useRouter()
    const { isAuthenticated, user, isSeller } = useAuthStore()

    const [step, setStep] = useState(1)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [applicationStatus, setApplicationStatus] = useState<'none' | 'pending' | 'rejected'>('none')
    const [isLoading, setIsLoading] = useState(true)

    // Form Data State
    const [formData, setFormData] = useState({
        business_type: 'individual' as BusinessType,
        store_name: '',
        store_slug: '',
        description: '',
        mobile_banking_provider: '',
        mobile_banking_number: '',
        accepted_terms: false
    })

    // Document Files State
    const [documents, setDocuments] = useState({
        profile_photo: null as File | null,
        nid_front: null as File | null,
        nid_back: null as File | null,
        student_id: null as File | null,
        trade_license: null as File | null,
        tin_certificate: null as File | null
    })

    const [previews, setPreviews] = useState<Record<string, string>>({})

    // Initial check
    useEffect(() => {
        if (!isAuthenticated) {
            router.push('/auth/login')
            return
        }

        if (isSeller()) {
            router.push('/seller/dashboard')
            return
        }

        // Check if an application is already pending
        api.get('/seller/application/status/')
            .then(res => {
                if (res.data.status === 'pending') {
                    setApplicationStatus('pending')
                } else if (res.data.status === 'rejected') {
                    setApplicationStatus('rejected')
                }
            })
            .catch(() => {
                // Ignore 404s, implies no application exists
            })
            .finally(() => setIsLoading(false))

    }, [isAuthenticated, isSeller, router])

    const updateFormData = (key: string, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }))
        // Auto generate slug if store name changes and slug hasn't been manually touched
        if (key === 'store_name' && !document.getElementById('store_slug')?.matches(':focus')) {
            const slug = value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '')
            setFormData(prev => ({ ...prev, [key]: value, store_slug: slug }))
        }
    }

    const handleFileUpload = (key: keyof typeof documents, e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        if (file.size > 10 * 1024 * 1024) {
            toast.error("File is too large. Maximum size is 10MB.")
            return
        }

        setDocuments(prev => ({ ...prev, [key]: file }))

        // Create preview
        if (previews[key]) URL.revokeObjectURL(previews[key])
        setPreviews(prev => ({ ...prev, [key]: URL.createObjectURL(file) }))
    }

    const removeFile = (key: keyof typeof documents) => {
        setDocuments(prev => ({ ...prev, [key]: null }))
        if (previews[key]) URL.revokeObjectURL(previews[key])
        setPreviews(prev => {
            const newPreviews = { ...prev }
            delete newPreviews[key]
            return newPreviews
        })
    }

    const validateStep1 = () => {
        if (!formData.business_type || !formData.store_name || !formData.store_slug || !formData.mobile_banking_provider || !formData.mobile_banking_number) {
            toast.error("Please fill in all required fields.")
            return false
        }
        return true
    }

    const validateStep2 = () => {
        if (!documents.profile_photo) {
            toast.error("Store Profile Photo is required.")
            return false
        }

        // Conditional validation
        if (formData.business_type === 'individual') {
            if (!documents.nid_front || !documents.nid_back) {
                toast.error("Both NID Front and Back are required for Individuals.")
                return false
            }
        } else if (formData.business_type === 'student_seller') {
            if (!documents.student_id || !documents.nid_front) {
                toast.error("Student ID and NID Front are required for Student Sellers.")
                return false
            }
        } else if (['business', 'official_store'].includes(formData.business_type)) {
            if (!documents.trade_license || !documents.tin_certificate) {
                toast.error("Trade License and TIN Certificate are required for Registered Businesses.")
                return false
            }
        }

        return true
    }

    const nextStep = () => {
        if (step === 1 && !validateStep1()) return
        if (step === 2 && !validateStep2()) return
        setStep(prev => prev + 1)
        window.scrollTo(0, 0)
    }

    const prevStep = () => {
        setStep(prev => prev - 1)
        window.scrollTo(0, 0)
    }

    const submitApplication = async () => {
        if (!formData.accepted_terms) {
            toast.error("You must accept the Seller Terms of Service.")
            return
        }

        setIsSubmitting(true)
        try {
            const payload = new FormData()
            Object.entries(formData).forEach(([key, value]) => payload.append(key, String(value)))

            // Append only the selected documents
            Object.entries(documents).forEach(([key, file]) => {
                if (file) payload.append(`doc_${key}`, file)
            })

            await api.post('/seller/register/', payload, {
                headers: { 'Content-Type': 'multipart/form-data' }
            })

            toast.success("Application submitted successfully!")
            setApplicationStatus('pending')
            window.scrollTo(0, 0)

        } catch (error: any) {
            toast.error(error.response?.data?.detail || "Failed to submit application. Please try again.")
        } finally {
            setIsSubmitting(false)
        }
    }

    if (isLoading) {
        return <div className="min-h-screen flex items-center justify-center bg-gray-50"><div className="animate-pulse font-bold text-brand-primary">Loading Application...</div></div>
    }

    // PENDING STATE VIEW
    if (applicationStatus === 'pending') {
        return (
            <div className="min-h-screen bg-[#F8FAFC] flex items-center justify-center p-4">
                <div className="bg-white max-w-lg w-full rounded-3xl shadow-xl p-8 sm:p-12 text-center border border-gray-100">
                    <div className="w-24 h-24 bg-blue-50 text-blue-500 rounded-full mx-auto flex items-center justify-center mb-6 ring-8 ring-blue-50/50">
                        <Store className="w-10 h-10" />
                    </div>
                    <h1 className="text-3xl font-extrabold text-[#1A1A2E] mb-3">Application Under Review</h1>
                    <p className="text-gray-500 mb-8 leading-relaxed text-sm sm:text-base">
                        Thanks for applying to be a seller! Our Trust & Safety team is reviewing your documents.
                        This process typically takes 24-48 business hours. We'll email you once it's approved.
                    </p>

                    <div className="bg-gray-50 rounded-2xl p-6 text-left border border-gray-100 relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
                        <h3 className="font-bold text-gray-900 mb-4 text-sm uppercase tracking-wider">Review Timeline</h3>
                        <div className="space-y-4">
                            <div className="flex gap-4">
                                <div className="mt-1"><CheckCircle2 className="w-5 h-5 text-blue-500" /></div>
                                <div>
                                    <p className="font-bold text-gray-900 text-sm">Application Submitted</p>
                                    <p className="text-xs text-gray-500">We've received your data.</p>
                                </div>
                            </div>
                            <div className="flex gap-4 opacity-50">
                                <div className="mt-1"><div className="w-5 h-5 rounded-full border-2 border-gray-300" /></div>
                                <div>
                                    <p className="font-bold text-gray-900 text-sm">Document Verification</p>
                                    <p className="text-xs text-gray-500">Authenticating IDs & Licenses</p>
                                </div>
                            </div>
                            <div className="flex gap-4 opacity-50">
                                <div className="mt-1"><div className="w-5 h-5 rounded-full border-2 border-gray-300" /></div>
                                <div>
                                    <p className="font-bold text-gray-900 text-sm">Final Decision</p>
                                    <p className="text-xs text-gray-500">Store activation</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    <Button onClick={() => router.push('/')} variant="outline" className="mt-8 w-full h-12 rounded-xl text-gray-600 font-bold border-gray-200 hover:bg-gray-50">
                        Return to Homepage
                    </Button>
                </div>
            </div>
        )
    }

    const businessTypes = [
        { id: 'individual', title: 'Individual', icon: User, desc: 'Selling used personal items or crafts' },
        { id: 'student_seller', title: 'Student Seller', icon: Verified, desc: 'Active student doing side-commerce' },
        { id: 'business', title: 'Business/Brand', icon: Store, desc: 'Registered small business with TIN' },
        { id: 'official_store', title: 'Official Store', icon: Building2, desc: 'Authorized distributor or parent brand' },
    ]

    const renderUploader = (key: keyof typeof documents, title: string, desc: string, required: boolean = true) => (
        <div key={key} className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
            <div className="flex justify-between items-start mb-4">
                <div>
                    <h3 className="font-bold text-gray-900">{title} {required && <span className="text-red-500">*</span>}</h3>
                    <p className="text-xs text-gray-500 mt-0.5">{desc}</p>
                </div>
            </div>

            {previews[key] ? (
                <div className="relative w-full h-48 rounded-xl overflow-hidden border border-gray-200 bg-white">
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img src={previews[key]} alt="Preview" className="w-full h-full object-contain" />
                    <button onClick={() => removeFile(key)} className="absolute top-2 right-2 bg-black/60 hover:bg-red-500 text-white p-2 rounded-full transition-colors">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            ) : (
                <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-gray-300 rounded-xl cursor-pointer hover:bg-white hover:border-brand-primary transition-all group">
                    <div className="flex flex-col items-center justify-center pt-5 pb-6">
                        <UploadCloud className="w-8 h-8 text-gray-400 group-hover:text-brand-primary mb-2" />
                        <p className="text-sm font-bold text-gray-600 group-hover:text-brand-primary">Click to upload or drag and drop</p>
                        <p className="text-xs text-gray-500 mt-1">PDF, JPG or PNG (MAX. 10MB)</p>
                    </div>
                    <input type="file" className="hidden" accept=".pdf,image/png,image/jpeg" onChange={(e) => handleFileUpload(key, e)} />
                </label>
            )}
        </div>
    )

    return (
        <div className="min-h-screen bg-[#F8FAFC]">
            {/* Header */}
            <header className="bg-white border-b border-gray-200 sticky top-0 z-10 shrink-0">
                <div className="max-w-4xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Store className="w-5 h-5 text-brand-primary" />
                        <span className="font-extrabold text-gray-900 tracking-tight">Become a Seller</span>
                    </div>
                    <button onClick={() => router.push('/')} className="text-sm font-bold text-gray-500 hover:text-gray-900">Cancel</button>
                </div>
            </header>

            <main className="max-w-4xl mx-auto px-4 sm:px-6 py-8 sm:py-12">
                {/* Progress Bar */}
                <div className="mb-12">
                    <div className="flex justify-between relative z-10">
                        {[1, 2, 3].map(num => (
                            <div key={num} className="flex flex-col items-center gap-2 bg-[#F8FAFC]">
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm border-2 transition-all ${step === num ? 'bg-brand-primary border-brand-primary text-white scale-110 shadow-lg shadow-brand-primary/20'
                                    : step > num ? 'bg-emerald-500 border-emerald-500 text-white' : 'bg-white border-gray-200 text-gray-400'
                                    }`}>
                                    {step > num ? <CheckCircle2 className="w-5 h-5" /> : num}
                                </div>
                                <span className={`text-xs font-bold uppercase tracking-wider hidden sm:block ${step >= num ? 'text-gray-900' : 'text-gray-400'}`}>
                                    {num === 1 ? 'Business Info' : num === 2 ? 'Documents' : 'Review'}
                                </span>
                            </div>
                        ))}
                    </div>
                    <div className="h-0.5 bg-gray-200 -mt-7 mb-7 mx-5 relative z-0">
                        <div className="h-full bg-emerald-500 transition-all duration-500 ease-out" style={{ width: `${((step - 1) / 2) * 100}%` }}></div>
                    </div>
                </div>

                <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
                    <div className="p-6 sm:p-10">
                        {/* STEP 1 */}
                        {step === 1 && (
                            <div className="space-y-8 animate-in slide-in-from-right-8 duration-500">
                                <div>
                                    <h2 className="text-2xl font-black text-gray-900">Tell us about your business</h2>
                                    <p className="text-gray-500 mt-1">Select the classification that best matches your commerce footprint.</p>
                                </div>

                                <div className="space-y-3">
                                    <Label className="text-sm font-bold text-gray-700">Business Type</Label>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        {businessTypes.map(type => {
                                            const Icon = type.icon
                                            const isSelected = formData.business_type === type.id
                                            return (
                                                <button
                                                    key={type.id}
                                                    type="button"
                                                    onClick={() => updateFormData('business_type', type.id)}
                                                    className={`p-4 rounded-2xl border-2 text-left transition-all flex gap-4 ${isSelected ? 'border-brand-primary bg-brand-primary/5 shadow-sm' : 'border-gray-200 hover:border-gray-300 hover:bg-gray-50'}`}
                                                >
                                                    <div className={`mt-0.5 ${isSelected ? 'text-brand-primary' : 'text-gray-400'}`}>
                                                        <Icon className="w-6 h-6" />
                                                    </div>
                                                    <div>
                                                        <p className={`font-bold ${isSelected ? 'text-brand-primary' : 'text-gray-900'}`}>{type.title}</p>
                                                        <p className="text-xs text-gray-500 mt-1">{type.desc}</p>
                                                    </div>
                                                </button>
                                            )
                                        })}
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold text-gray-700">Store Name <span className="text-red-500">*</span></Label>
                                        <Input
                                            placeholder="e.g. Campus Tech Stop"
                                            value={formData.store_name}
                                            onChange={e => updateFormData('store_name', e.target.value)}
                                            className="h-12 bg-gray-50 border-gray-200 focus-visible:ring-brand-primary focus-visible:bg-white"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold text-gray-700">Store Slug URL <span className="text-red-500">*</span></Label>
                                        <div className="flex">
