    const tabs: { id: OrderStatus, label: string }[] = [
        { id: 'all', label: 'All Orders' },
        { id: 'pending', label: 'Pending' },
        { id: 'confirmed', label: 'Confirmed' },
        { id: 'packed', label: 'Packed' },
        { id: 'shipped', label: 'Shipped' },
        { id: 'delivered', label: 'Delivered' },
        { id: 'cancelled', label: 'Cancelled' },
    ]

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'pending': return 'bg-amber-50 text-amber-700 border-amber-200'
            case 'confirmed': return 'bg-blue-50 text-blue-700 border-blue-200'
            case 'packed': return 'bg-indigo-50 text-indigo-700 border-indigo-200'
            case 'shipped': return 'bg-purple-50 text-purple-700 border-purple-200'
            case 'delivered': return 'bg-emerald-50 text-emerald-700 border-emerald-200'
            case 'cancelled': return 'bg-red-50 text-red-700 border-red-200'
            default: return 'bg-gray-100 text-gray-700 border-gray-200'
        }
    }

    const updateOrderStatus = (id: string, newStatus: OrderStatus) => {
        setOrders(orders.map(o => o.id === id ? { ...o, status: newStatus } : o))
        toast.success(`Order ${id} marked as ${newStatus}`)
    }

    const openShipModal = (order: any) => {
        setSelectedOrder(order)
        setShipData({ courier: '', tracking_code: '' })
        setIsShipModalOpen(true)
    }

    const handleShipOrder = () => {
        if (!shipData.courier || !shipData.tracking_code) {
            toast.error("Please provide both courier and tracking code")
            return
        }
        setOrders(orders.map(o => o.id === selectedOrder.id ? { ...o, status: 'shipped', courier: shipData.courier, tracking: shipData.tracking_code } : o))
        toast.success(`Order ${selectedOrder.id} has been shipped via ${shipData.courier}`)
        setIsShipModalOpen(false)
    }

    return (
        <div className="space-y-6 max-w-6xl mx-auto">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-black text-gray-900">Orders Management</h1>
                <p className="text-gray-500 text-sm mt-1">Review, process, and track your store orders.</p>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                    <p className="text-sm font-bold text-gray-500 mb-1">To Confirm</p>
                    <p className="text-2xl font-black text-amber-600">{orders.filter(o => o.status === 'pending').length}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                    <p className="text-sm font-bold text-gray-500 mb-1">To Pack</p>
                    <p className="text-2xl font-black text-blue-600">{orders.filter(o => o.status === 'confirmed').length}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                    <p className="text-sm font-bold text-gray-500 mb-1">To Ship</p>
                    <p className="text-2xl font-black text-indigo-600">{orders.filter(o => o.status === 'packed').length}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                    <p className="text-sm font-bold text-gray-500 mb-1">In Transit</p>
                    <p className="text-2xl font-black text-purple-600">{orders.filter(o => o.status === 'shipped').length}</p>
                </div>
            </div>

            {/* Tabs & Search */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-100 overflow-x-auto no-scrollbar">
                    {tabs.map(tab => {
                        const count = tab.id === 'all' ? orders.length : orders.filter(o => o.status === tab.id).length
                        return (
                            <button
                                key={tab.id}
                                onClick={() => setCurrentTab(tab.id)}
                                className={`flex items-center gap-2 px-6 py-4 text-sm font-bold border-b-2 whitespace-nowrap transition-colors
                                    ${currentTab === tab.id
                                        ? 'border-brand-primary text-brand-primary bg-brand-primary/5'
                                        : 'border-transparent text-gray-500 hover:text-gray-900 hover:bg-gray-50'
                                    }
                                `}
                            >
                                {tab.label}
                                <span className={`px-2 py-0.5 rounded-full text-[10px] ${currentTab === tab.id ? 'bg-brand-primary text-white' : 'bg-gray-100 text-gray-600'}`}>
                                    {count}
                                </span>
                            </button>
                        )
                    })}
                </div>
                <div className="p-4 flex gap-4 bg-gray-50/50">
                    <div className="relative flex-1 max-w-md">
                        <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <Input
                            placeholder="Search Order ID or Buyer Name..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            className="h-10 pl-9 bg-white border-gray-200"
                        />
                    </div>
                </div>
            </div>

            {/* Orders List */}
            <div className="space-y-4">
                {isLoading ? (
                    <div className="text-center py-12 text-gray-500 animate-pulse font-bold bg-white rounded-xl border border-gray-200">Loading orders...</div>
                ) : filteredOrders.length === 0 ? (
                    <div className="text-center py-16 bg-white rounded-xl border border-gray-200 shadow-sm">
                        <PackageIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                        <p className="font-bold text-gray-900">No orders found</p>
                        <p className="text-sm text-gray-500 mt-1">There are no orders matching this status or search.</p>
                    </div>
                ) : filteredOrders.map(order => (
                    <div key={order.id} className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden transition-all hover:border-gray-300">
                        {/* Summary Header */}
                        <div className="p-5 flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b border-gray-100">
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-xl bg-gray-50 border border-gray-100 flex items-center justify-center shrink-0">
                                    <ShoppingBag className="w-5 h-5 text-brand-primary" />
                                </div>
                                <div>
                                    <div className="flex items-center gap-3">
                                        <h3 className="font-black text-gray-900">{order.id}</h3>
                                        <Badge variant="outline" className={`uppercase tracking-wider text-[10px] font-bold ${getStatusColor(order.status)}`}>
                                            {order.status}
                                        </Badge>
                                    </div>
                                    <p className="text-xs text-gray-500 mt-1">{order.date} • {order.items.length} Items</p>
                                </div>
                            </div>
                            <div className="flex flex-col sm:items-end md:ml-auto">
                                <p className="text-xs text-gray-500 font-bold uppercase tracking-wider">Total Amount</p>
                                <p className="font-black text-gray-900 sm:text-lg">৳{order.total.toLocaleString()}</p>
                            </div>

                            {/* Action Buttons based on status */}
                            <div className="flex flex-wrap gap-2 mt-2 sm:mt-0">
                                {order.status === 'pending' && (
                                    <Button onClick={() => updateOrderStatus(order.id, 'confirmed')} className="bg-blue-600 hover:bg-blue-700 text-white font-bold h-9">
                                        <CheckCircle2 className="w-4 h-4 mr-1.5" /> Confirm Order
                                    </Button>
                                )}
                                {order.status === 'confirmed' && (
                                    <Button onClick={() => updateOrderStatus(order.id, 'packed')} className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold h-9">
                                        <Box className="w-4 h-4 mr-1.5" /> Mark as Packed
                                    </Button>
                                )}
                                {order.status === 'packed' && (
                                    <Button onClick={() => openShipModal(order)} className="bg-purple-600 hover:bg-purple-700 text-white font-bold h-9">
                                        <Truck className="w-4 h-4 mr-1.5" /> Ship Order
                                    </Button>
                                )}

                                <Button
                                    variant="outline"
                                    onClick={() => setExpandedOrderId(expandedOrderId === order.id ? null : order.id)}
                                    className="h-9 font-bold text-gray-600"
                                >
                                    {expandedOrderId === order.id ? 'Hide Details' : 'View Details'}
                                </Button>
                            </div>
                        </div>

                        {/* Expanded Content */}
                        {expandedOrderId === order.id && (
                            <div className="bg-gray-50/50 p-5 grid grid-cols-1 md:grid-cols-2 gap-8 border-t border-gray-100 animate-in slide-in-from-top-2 duration-200">
                                {/* Left Side: Items list */}
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm mb-3">Ordered Items</h4>
                                    <div className="bg-white border border-gray-200 rounded-xl overflow-hidden divide-y divide-gray-100">
                                        {order.items.map((item: any, i: number) => (
                                            <div key={i} className="p-3 flex items-center gap-3">
                                                <img src={item.image} alt={item.name} className="w-10 h-10 rounded border border-gray-200 shrink-0" />
                                                <div className="flex-1 min-w-0">
                                                    <p className="font-bold text-gray-900 text-sm truncate">{item.name}</p>
                                                    <p className="text-xs text-gray-500">Qty: {item.qty} × ৳{item.price}</p>
                                                </div>
                                                <div className="font-black text-gray-900">৳{item.price * item.qty}</div>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="mt-3 bg-white p-3 rounded-xl border border-gray-200 flex justify-between items-center text-sm">
                                        <span className="font-bold text-gray-500">Payment Method</span>
                                        <div className="flex items-center gap-1 font-bold text-gray-900">
                                            <CreditCard className="w-4 h-4 text-emerald-600" /> Cash on Delivery
                                        </div>
                                    </div>
                                </div>

                                {/* Right Side: Delivery Details */}
                                <div>
                                    <h4 className="font-bold text-gray-900 text-sm mb-3">Delivery Information</h4>
                                    <div className="bg-white border border-gray-200 rounded-xl p-4 space-y-4">
                                        <div className="flex gap-3">
                                            <User className="w-4 h-4 text-gray-400 translate-y-0.5" />
                                            <div>
                                                <p className="font-bold text-gray-900 text-sm">{order.buyer.name}</p>
                                                <p className="text-xs text-gray-500 mt-0.5">{order.buyer.phone}</p>
                                            </div>
                                        </div>
                                        <div className="flex gap-3">
                                            <MapPin className="w-4 h-4 text-gray-400 translate-y-0.5" />
                                            <div>
                                                <p className="font-bold text-gray-900 text-sm">Shipping Address</p>
                                                <p className="text-xs text-gray-500 mt-0.5 leading-relaxed">{order.address}</p>
                                            </div>
                                        </div>
                                        {order.tracking && (
                                            <div className="flex gap-3 pt-3 border-t border-gray-100">
                                                <Map className="w-4 h-4 text-brand-primary translate-y-0.5" />
                                                <div>
                                                    <p className="font-bold text-gray-900 text-sm">Tracking: {order.tracking}</p>
                                                    <p className="text-xs text-gray-500 mt-0.5">Dispatched via {order.courier}</p>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                ))}
            </div>

            {/* Courier Ship Modal */}
            <Dialog open={isShipModalOpen} onOpenChange={setIsShipModalOpen}>
                <DialogContent>
                    <DialogTitle className="font-black text-xl">Ship Order {selectedOrder?.id}</DialogTitle>
                    <div className="space-y-4 py-4">
                        <div className="bg-purple-50 p-4 rounded-xl border border-purple-100 flex gap-4">
                            <Truck className="w-6 h-6 text-brand-primary shrink-0" />
                            <div>
                                <p className="font-bold text-brand-primary text-sm">Ready to Ship</p>
                                <p className="text-xs text-purple-700/70 mt-1">Provide the courier tracking details. The customer will be notified via email automatically.</p>
                            </div>
                        </div>

                        <div className="space-y-2 text-left">
                            <Label className="font-bold">Courier Service <span className="text-red-500">*</span></Label>
                            <Select value={shipData.courier} onValueChange={v => setShipData({ ...shipData, courier: v })}>
                                <SelectTrigger className="h-11">
                                    <SelectValue placeholder="Select courier..." />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="Pathao">Pathao Courier</SelectItem>
                                    <SelectItem value="RedX">RedX Logistics</SelectItem>
                                    <SelectItem value="Steadfast">Steadfast Courier</SelectItem>
                                    <SelectItem value="Sundarban">Sundarban Courier</SelectItem>
                                    <SelectItem value="Self_Delivery">Self / Campus Delivery</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="space-y-2 text-left">
                            <Label className="font-bold">Tracking Code / Package ID <span className="text-red-500">*</span></Label>
                            <Input
                                placeholder="e.g. PTH-123456"
                                value={shipData.tracking_code}
                                onChange={e => setShipData({ ...shipData, tracking_code: e.target.value })}
                                className="h-11 font-medium"
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsShipModalOpen(false)} className="font-bold">Cancel</Button>
                        <Button onClick={handleShipOrder} className="bg-brand-primary hover:bg-brand-primary/90 text-white font-bold">
                            <Truck className="w-4 h-4 mr-2" /> Dispatch Package
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import {
    Plus, Search, Edit2, Trash2, Image as ImageIcon,
    MoreHorizontal, Filter, ArrowUpDown, X, UploadCloud, GripVertical, Package
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Switch } from '@/components/ui/switch'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Dialog, DialogContent, DialogTitle, DialogFooter } from '@/components/ui/dialog'
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu'
import { toast } from 'react-hot-toast'

interface ProductVariant {
    id: string
    color: string
    size: string
    price: number | string
    stock: number | string
}

export default function SellerProductsPage() {
    const [products, setProducts] = useState<any[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState('')

    // Product Modal State
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [editingProduct, setEditingProduct] = useState<any>(null)
    const [isSaving, setIsSaving] = useState(false)

    // Form State
    const [formData, setFormData] = useState({
        name: '', category: '', description: '',
        base_price: '', discount_price: '', sku: '',
        stock_quantity: '', is_active: true
    })
    const [tags, setTags] = useState<string[]>([])
    const [tagInput, setTagInput] = useState('')

    // Variants State
    const [variants, setVariants] = useState<ProductVariant[]>([])

    // Images State
    const [images, setImages] = useState<{ id: string, file?: File, url?: string }[]>([])

    useEffect(() => {
        // Mock API Fetch
        setTimeout(() => {
            setProducts([
                { id: '1', image: 'https://placehold.co/80x80/purple/white', name: 'Campus Backpack 2024', category: 'Accessories', price: 1500, stock: 45, status: 'active', created_at: '2024-06-15' },
                { id: '2', image: 'https://placehold.co/80x80/blue/white', name: 'Mechanical Keyboard Blue Switch', category: 'Electronics', price: 4200, stock: 12, status: 'active', created_at: '2024-06-20' },
                { id: '3', image: 'https://placehold.co/80x80/gray/white', name: 'University Hoodie (L)', category: 'Clothing', price: 850, stock: 0, status: 'out_of_stock', created_at: '2024-06-22' },
                { id: '4', image: null, name: 'Data Structures Notes', category: 'Education', price: 200, stock: 999, status: 'draft', created_at: '2024-06-25' }
            ])
            setIsLoading(false)
        }, 600)
    }, [])

    const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()))

    const openAddModal = () => {
        setEditingProduct(null)
        setFormData({ name: '', category: '', description: '', base_price: '', discount_price: '', sku: '', stock_quantity: '1', is_active: true })
        setTags([])
        setVariants([])
        setImages([])
        setIsModalOpen(true)
    }

    const openEditModal = (product: any) => {
        setEditingProduct(product)
        setFormData({
            name: product.name, category: product.category, description: 'Mock description...',
            base_price: product.price.toString(), discount_price: '', sku: `SKU-${product.id}`,
            stock_quantity: product.stock.toString(), is_active: product.status === 'active'
        })
        setTags(['sale', product.category.toLowerCase()])
        setVariants(product.category === 'Clothing' ? [{ id: '1', color: 'Black', size: 'M', price: 850, stock: 5 }] : [])

        setImages(product.image ? [{ id: 'img1', url: product.image }] : [])
        setIsModalOpen(true)
    }

    const deleteProduct = (id: string, name: string) => {
        if (confirm(`Are you sure you want to delete ${name}?`)) {
            setProducts(prev => prev.filter(p => p.id !== id))
            toast.success("Product deleted successfully")
        }
    }

    const duplicateProduct = (product: any) => {
        const newProduct = { ...product, id: Date.now().toString(), name: `${product.name} (Copy)`, status: 'draft' }
        setProducts([newProduct, ...products])
        toast.success("Product duplicated to drafts")
    }

    // Modal Handlers
    const addTag = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && tagInput.trim()) {
            e.preventDefault()
            if (!tags.includes(tagInput.trim())) setTags([...tags, tagInput.trim()])
            setTagInput('')
        }
    }

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || [])
        if (images.length + files.length > 10) {
            toast.error("Maximum 10 images allowed")
            return
        }

        const newImages = files.map(file => ({
            id: Math.random().toString(36).substring(7),
            file,
            url: URL.createObjectURL(file)
        }))
        setImages([...images, ...newImages])
    }

    const addVariant = () => {
        setVariants([...variants, { id: Date.now().toString(), color: '', size: '', price: formData.base_price || 0, stock: 0 }])
    }

    const updateVariant = (id: string, field: string, value: string) => {
        setVariants(variants.map(v => v.id === id ? { ...v, [field]: value } : v))
    }

    const removeVariant = (id: string) => {
        setVariants(variants.filter(v => v.id !== id))
    }

    const saveProduct = () => {
        setIsSaving(true)
        setTimeout(() => {
            if (editingProduct) {
                setProducts(products.map(p => p.id === editingProduct.id ? {
                    ...p, name: formData.name, category: formData.category, price: Number(formData.base_price),
                    stock: variants.length > 0 ? variants.reduce((sum, v) => sum + Number(v.stock), 0) : Number(formData.stock_quantity),
                    status: formData.is_active ? 'active' : 'draft',
                    image: images[0]?.url || null
                } : p))
                toast.success("Product updated successfully")
            } else {
                const newId = Date.now().toString()
                setProducts([{
                    id: newId, name: formData.name, category: formData.category, price: Number(formData.base_price),
                    stock: variants.length > 0 ? variants.reduce((sum, v) => sum + Number(v.stock), 0) : Number(formData.stock_quantity),
                    status: formData.is_active ? 'active' : 'draft',
                    created_at: new Date().toISOString().split('T')[0],
                    image: images[0]?.url || null
                }, ...products])
                toast.success("Product created successfully")
            }
            setIsSaving(false)
            setIsModalOpen(false)
        }, 1000)
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-gray-900">My Products</h1>
                    <p className="text-gray-500 text-sm mt-1">Manage your catalog, inventory, and pricing.</p>
                </div>
                <Button onClick={openAddModal} className="bg-brand-primary hover:bg-brand-primary/90 text-white shadow-md">
                    <Plus className="w-5 h-5 mr-2" /> Add Product
                </Button>
            </div>

            {/* Filters */}
            <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                    <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <Input
                        placeholder="Search products by name or SKU..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="pl-10 h-11 border-gray-200"
                    />
                </div>
                <div className="flex gap-2">
                    <Button variant="outline" className="h-11 border-gray-200 text-gray-600">
                        <Filter className="w-4 h-4 mr-2" /> Category
                    </Button>
                    <Button variant="outline" className="h-11 border-gray-200 text-gray-600">
                        <Filter className="w-4 h-4 mr-2" /> Status
                    </Button>
                </div>
            </div>

            {/* Table */}
            <div className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-200 text-xs font-black uppercase text-gray-500 tracking-wider">
                                <th className="p-4 font-bold">Product Name</th>
                                <th className="p-4 font-bold cursor-pointer hover:bg-gray-100 group"><div className="flex items-center gap-1">Category <ArrowUpDown className="w-3 h-3 opacity-0 group-hover:opacity-100" /></div></th>
                                <th className="p-4 font-bold cursor-pointer hover:bg-gray-100 group"><div className="flex items-center gap-1">Price <ArrowUpDown className="w-3 h-3 opacity-0 group-hover:opacity-100" /></div></th>
                                <th className="p-4 font-bold cursor-pointer hover:bg-gray-100 group"><div className="flex items-center gap-1">Stock <ArrowUpDown className="w-3 h-3 opacity-0 group-hover:opacity-100" /></div></th>
                                <th className="p-4 font-bold">Status</th>
                                <th className="p-4 font-bold text-center">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 text-sm">
                            {isLoading ? (
                                <tr><td colSpan={6} className="p-8 text-center text-gray-500 animate-pulse">Loading products...</td></tr>
                            ) : filteredProducts.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="p-12 text-center text-gray-500">
                                        <Package className="w-12 h-12 mx-auto text-gray-300 mb-3" />
                                        <p className="font-bold text-gray-900">No products found</p>
                                        <p className="text-sm mt-1">Try adjusting your search filters.</p>
                                    </td>
                                </tr>
                            ) : filteredProducts.map(product => (
                                <tr key={product.id} className="hover:bg-gray-50/50 transition-colors">
                                    <td className="p-4">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-12 rounded-lg bg-gray-100 border border-gray-200 overflow-hidden flex items-center justify-center shrink-0">
                                                {product.image ? <img src={product.image} alt={product.name} className="w-full h-full object-cover" /> : <ImageIcon className="w-5 h-5 text-gray-400" />}
                                            </div>
                                            <div>
                                                <p className="font-bold text-gray-900">{product.name}</p>
                                                <p className="text-[11px] text-gray-500 mt-0.5">ID: {product.id} • Added {product.created_at}</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-4 text-gray-600 font-medium">{product.category}</td>
                                    <td className="p-4 font-bold text-gray-900">৳{product.price.toLocaleString()}</td>
                                    <td className="p-4">
                                        <span className={`font-bold ${product.stock > 10 ? 'text-emerald-600' : product.stock > 0 ? 'text-amber-600' : 'text-red-500'}`}>
                                            {product.stock} in stock
                                        </span>
                                    </td>
                                    <td className="p-4">
                                        <Badge variant="outline" className={`
                                            ${product.status === 'active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : ''}
                                            ${product.status === 'draft' ? 'bg-gray-100 text-gray-700 border-gray-300' : ''}
                                            ${product.status === 'out_of_stock' ? 'bg-red-50 text-red-700 border-red-200' : ''}
                                        `}>
                                            {product.status.replace('_', ' ').toUpperCase()}
                                        </Badge>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center justify-center gap-2">
                                            <Button variant="ghost" size="icon" onClick={() => openEditModal(product)} className="text-brand-primary hover:bg-brand-primary/10">
                                                <Edit2 className="w-4 h-4" />
                                            </Button>
                                            <DropdownMenu>
                                                <DropdownMenuTrigger asChild>
                                                    <Button variant="ghost" size="icon" className="text-gray-400 hover:text-gray-900">
                                                        <MoreHorizontal className="w-4 h-4" />
                                                    </Button>
                                                </DropdownMenuTrigger>
                                                <DropdownMenuContent align="end" className="w-40 font-medium">
                                                    <DropdownMenuItem onClick={() => duplicateProduct(product)}>Duplicate Product</DropdownMenuItem>
                                                    <div className="h-px bg-gray-100 my-1" />
                                                    <DropdownMenuItem onClick={() => deleteProduct(product.id, product.name)} className="text-red-600 focus:text-red-600 focus:bg-red-50">
                                                        <Trash2 className="w-4 h-4 mr-2" /> Delete
                                                    </DropdownMenuItem>
                                                </DropdownMenuContent>
                                            </DropdownMenu>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <div className="p-4 border-t border-gray-200 flex items-center justify-between text-sm text-gray-500 font-medium">
                    <span>Showing 1 to {filteredProducts.length} of {filteredProducts.length} results</span>
                    <div className="flex gap-2">
                        <Button variant="outline" disabled className="h-8">Previous</Button>
                        <Button variant="outline" disabled className="h-8">Next</Button>
                    </div>
                </div>
            </div>

            {/* ADD / EDIT MODAL (Full Screen Overlay) */}
            <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
                <DialogContent className="max-w-4xl p-0 h-[90vh] flex flex-col bg-gray-50/50">
                    <div className="p-6 border-b border-gray-200 bg-white sticky top-0 z-10 flex justify-between items-center">
                        <div>
                            <DialogTitle className="text-xl font-black text-gray-900">{editingProduct ? 'Edit Product' : 'Add New Product'}</DialogTitle>
                            <p className="text-sm text-gray-500 mt-1">Configure your product details, variants, and inventory.</p>
                        </div>
                        <div className="flex items-center gap-3">
                            <Label htmlFor="publish-toggle" className="font-bold text-gray-700">{formData.is_active ? 'Active' : 'Draft'}</Label>
                            <Switch id="publish-toggle" checked={formData.is_active} onCheckedChange={c => setFormData({ ...formData, is_active: c })} className="data-[state=checked]:bg-emerald-500" />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-6">
                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                            {/* Left Column: Form Details */}
                            <div className="lg:col-span-2 space-y-8">
                                {/* Basic Info */}
                                <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-5">
                                    <h3 className="font-bold text-gray-900 border-b border-gray-100 pb-2">Basic Information</h3>
                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Product Name <span className="text-red-500">*</span></Label>
                                            <Input value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className="h-11 bg-gray-50" placeholder="e.g. Nike Air Force 1" />
                                        </div>
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-2">
                                                <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Store Category <span className="text-red-500">*</span></Label>
                                                <Select value={formData.category} onValueChange={v => setFormData({ ...formData, category: v })}>
                                                    <SelectTrigger className="h-11 bg-gray-50"><SelectValue placeholder="Select..." /></SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="Clothing">Clothing</SelectItem>
                                                        <SelectItem value="Electronics">Electronics</SelectItem>
                                                        <SelectItem value="Accessories">Accessories</SelectItem>
                                                        <SelectItem value="Education">Education</SelectItem>
                                                    </SelectContent>
                                                </Select>
                                            </div>
                                            <div className="space-y-2">
                                                <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Search Tags</Label>
                                                <Input value={tagInput} onChange={e => setTagInput(e.target.value)} onKeyDown={addTag} className="h-11 bg-gray-50" placeholder="Type & Enter to add" />
                                                <div className="flex flex-wrap gap-2 pt-2">
                                                    {tags.map(tag => (
                                                        <Badge key={tag} className="px-2 py-1 bg-gray-100 text-gray-700 border-gray-200 font-bold hover:bg-gray-200">
                                                            {tag} <X className="w-3 h-3 ml-1 cursor-pointer" onClick={() => setTags(tags.filter(t => t !== tag))} />
                                                        </Badge>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Product Description</Label>
                                            <Textarea value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} rows={5} className="resize-none bg-gray-50" placeholder="Describe the item, materials, sizing, etc." />
                                        </div>
                                    </div>
                                </div>

                                {/* Variants Section */}
                                <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-5">
                                    <div className="flex justify-between items-center border-b border-gray-100 pb-2">
                                        <h3 className="font-bold text-gray-900">Product Variants</h3>
                                        <Button variant="outline" size="sm" onClick={addVariant} className="text-brand-primary border-brand-primary/20 hover:bg-brand-primary/10">
                                            <Plus className="w-4 h-4 mr-1" /> Add Variant
                                        </Button>
                                    </div>

                                    {variants.length === 0 ? (
                                        <div className="text-center py-6 text-gray-500 text-sm bg-gray-50 rounded-xl border border-gray-100 border-dashed">
                                            Does this product have options like size or color?<br />
                                            If yes, add variants. Otherwise, it will be treated as single-stock.
                                        </div>
                                    ) : (
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-sm text-left">
                                                <thead>
                                                    <tr className="bg-gray-50 text-xs uppercase font-bold text-gray-500">
                                                        <th className="p-3 rounded-tl-lg">Color/Style</th>
                                                        <th className="p-3">Size/Type</th>
                                                        <th className="p-3">Price (৳)</th>
                                                        <th className="p-3">Stock Limit</th>
                                                        <th className="p-3 rounded-tr-lg"></th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {variants.map(variant => (
                                                        <tr key={variant.id} className="border-b border-gray-50">
                                                            <td className="p-2"><Input value={variant.color} onChange={e => updateVariant(variant.id, 'color', e.target.value)} placeholder="e.g. Red" className="h-9 bg-white" /></td>
                                                            <td className="p-2"><Input value={variant.size} onChange={e => updateVariant(variant.id, 'size', e.target.value)} placeholder="e.g. XL" className="h-9 bg-white" /></td>
                                                            <td className="p-2"><Input type="number" value={variant.price} onChange={e => updateVariant(variant.id, 'price', e.target.value)} className="h-9 bg-white w-24" /></td>
                                                            <td className="p-2"><Input type="number" value={variant.stock} onChange={e => updateVariant(variant.id, 'stock', e.target.value)} className="h-9 bg-white w-24" /></td>
                                                            <td className="p-2 justify-end flex"><Button variant="ghost" size="icon" onClick={() => removeVariant(variant.id)} className="text-gray-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></Button></td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                            <p className="text-xs text-gray-500 mt-2 font-medium">When variants exist, root pricing/stock is ignored. Totals are derived dynamically.</p>
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* Right Column: Pricing & Images */}
                            <div className="space-y-8">
                                {/* Pricing & Inventory (Hidden root if variants exist) */}
                                <div className={`bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-5 transition-opacity ${variants.length > 0 ? 'opacity-50 pointer-events-none grayscale' : ''}`}>
                                    <h3 className="font-bold text-gray-900 border-b border-gray-100 pb-2">Pricing & Inventory</h3>
                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Base Price (৳) <span className="text-red-500">*</span></Label>
                                            <Input type="number" value={formData.base_price} onChange={e => setFormData({ ...formData, base_price: e.target.value })} className="h-11 bg-gray-50 font-black text-gray-900" placeholder="0.00" />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Available Stock</Label>
                                            <Input type="number" value={formData.stock_quantity} onChange={e => setFormData({ ...formData, stock_quantity: e.target.value })} className="h-11 bg-gray-50" placeholder="10" />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500 flex justify-between">
                                                Compare at Price <span className="text-[10px] text-gray-400 normal-case">(Optional Sale)</span>
                                            </Label>
                                            <Input type="number" value={formData.discount_price} onChange={e => setFormData({ ...formData, discount_price: e.target.value })} className="h-11 bg-gray-50 line-through text-gray-400" placeholder="0.00" />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="font-bold text-xs uppercase tracking-wider text-gray-500">Stock Keeping Unit (SKU)</Label>
                                            <Input value={formData.sku} onChange={e => setFormData({ ...formData, sku: e.target.value })} className="h-11 bg-gray-50 text-xs" placeholder="e.g. TSHIRT-RED-XL" />
                                        </div>
                                    </div>
                                </div>

                                {/* Media Uploader */}
                                <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-4">
                                    <div className="flex justify-between items-end border-b border-gray-100 pb-2">
                                        <h3 className="font-bold text-gray-900">Product Media</h3>
                                        <span className="text-xs font-bold text-gray-400">{images.length}/10 Images</span>
                                    </div>

                                    {/* Upload Dropzone */}
                                    <label className={`w-full h-32 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-colors ${images.length >= 10 ? 'opacity-50 border-gray-200 bg-gray-50 pointer-events-none' : 'border-gray-300 bg-gray-50 hover:bg-white hover:border-brand-primary'}`}>
                                        <UploadCloud className="w-6 h-6 text-gray-400 mb-2" />
                                        <span className="text-sm font-bold text-gray-600">Drag & Drop or <span className="text-brand-primary">Click</span></span>
                                        <span className="text-xs text-gray-400 mt-1">Accepts JPG/PNG up to 5MB</span>
                                        <input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} disabled={images.length >= 10} />
                                    </label>

                                    {/* Image Grid */}
                                    {images.length > 0 && (
                                        <div className="grid grid-cols-3 gap-2 mt-4">
                                            {images.map((img, i) => (
                                                <div key={img.id} className="relative aspect-square rounded-lg border border-gray-200 overflow-hidden group bg-gray-100">
                                                    <img src={img.url} alt="Preview" className="w-full h-full object-cover" />
                                                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                                        <button type="button" className="text-white hover:text-brand-primary bg-black/50 p-1.5 rounded-full"><GripVertical className="w-3 h-3" /></button>
                                                        <button type="button" onClick={() => setImages(images.filter(x => x.id !== img.id))} className="text-white hover:text-red-500 bg-black/50 p-1.5 rounded-full"><Trash2 className="w-3 h-3" /></button>
                                                    </div>
                                                    {i === 0 && <span className="absolute bottom-0 left-0 right-0 bg-brand-primary/90 text-[9px] text-white font-bold text-center py-0.5">COVER PHOTO</span>}
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-4 sm:p-6 border-t border-gray-200 bg-white sticky bottom-0 z-10 flex justify-end gap-3">
                        <Button variant="outline" onClick={() => setIsModalOpen(false)} className="font-bold hover:bg-gray-50 text-gray-600">Cancel</Button>
                        <Button
                            onClick={saveProduct}
                            disabled={isSaving || !formData.name || !formData.category}
                            className="bg-brand-primary hover:bg-brand-primary/90 text-white font-bold shadow-lg shadow-brand-primary/20"
                        >
                            {isSaving ? 'Processing Content...' : editingProduct ? 'Save Changes' : 'Publish Product'}
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { GraduationCap, X } from 'lucide-react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'

import { useAuthStore } from '@/stores/auth.store'
import { Button } from '@/components/ui/button'
import { Dialog, DialogContent } from '@/components/ui/dialog'

export function VerificationRequiredCard({
    isOpen,
    onClose,
}: {
    isOpen: boolean
    onClose: () => void
}) {
    const handleDismiss = () => {
        sessionStorage.setItem('dismissedVerification', 'true')
        onClose()
    }

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && handleDismiss()}>
            <DialogContent className="sm:max-w-sm p-6 text-center">
                <div className="flex justify-center mb-4">
                    <div className="w-16 h-16 bg-brand-light rounded-full flex items-center justify-center">
                        <GraduationCap className="h-8 w-8 text-brand-primary" />
                    </div>
                </div>

                <h2 className="text-2xl font-bold text-gray-900 mb-2">Verification Required</h2>

                <p className="text-sm text-gray-500 mb-6 leading-relaxed">
                    If you are a student, please verify your{' '}
                    <Link href="/account/verify" className="text-brand-primary underline font-medium hover:text-brand-dark transition-colors">
                        student status
                    </Link>{' '}
                    to unlock student-only features.
                </p>

                <div className="space-y-3">
                    <Link href="/account/verify" className="block w-full">
                        <Button className="w-full">
                            Verify as Student
                        </Button>
                    </Link>

                    <Button
                        variant="outline"
                        className="w-full text-muted-foreground"
                        onClick={handleDismiss}
                    >
                        Continue as Regular User
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    )
}

export function VerificationBanner() {
    const { user, isAuthenticated, isVerifiedStudent, isSeller } = useAuthStore()
    const [isVisible, setIsVisible] = useState(false)

    useEffect(() => {
        // Only show if authenticated, not verified implicitly or explicitly, and not dismissed
        const isDismissed = sessionStorage.getItem('dismissedVerification') === 'true'

        if (isAuthenticated && !isVerifiedStudent() && !isSeller() && !isDismissed) {
            setIsVisible(true)
        }
    }, [isAuthenticated, isVerifiedStudent, isSeller])

    if (!isVisible) return null

    return (
        <div className="bg-brand-light border-b border-brand-light/20 py-3 relative">
            <div className="container mx-auto px-4 pr-10 flex flex-col sm:flex-row items-center justify-center gap-2 text-center sm:text-left text-brand-dark text-sm">
                <span>
                    <GraduationCap className="inline-block h-4 w-4 mr-1 text-brand-primary" />
                    <strong>Student?</strong> Verify your university ID to unlock exclusive campus prices and features.
                </span>
                <Link href="/account/verify" className="font-bold underline text-brand-primary hover:text-brand-dark">
                    Verify Now
                </Link>
            </div>
            <button
                onClick={() => {
                    sessionStorage.setItem('dismissedVerification', 'true')
                    setIsVisible(false)
                }}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-brand-primary/60 hover:text-brand-primary"
                aria-label="Dismiss banner"
            >
                <X className="h-4 w-4" />
            </button>
        </div>
    )
}

'use client'

import React, { useState } from 'react'
import Image from 'next/image'
import Link from 'next/link'
import { Heart, ShoppingBag } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import toast from 'react-hot-toast'

import { Card } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { useCartStore } from '@/stores/cart.store'
import { DiscountBadge } from '@/components/shared/DiscountBadge'
import { StockBadge } from '@/components/shared/StockBadge'
import { StarRating } from '@/components/shared/StarRating'
import { CurrencyDisplay } from '@/components/shared/CurrencyDisplay'
import { cn } from '@/lib/utils'

export interface Product {
    id: string
    slug: string
    name: string
    category_name: string
    base_price: string
    discount_price?: string | null
    images: { id: string, image_url: string, is_primary: boolean }[]
    stock_quantity: number
    has_variants: boolean
    rating_avg: number
    rating_count: number
    is_featured: boolean
    tags?: string[]
}

interface ProductCardProps {
    product: Product
}

export function ProductCard({ product }: ProductCardProps) {
    const { addItem } = useCartStore()
    const [isWishlisted, setIsWishlisted] = useState(false) // Optimistic state for now

    const primaryImage = product.images.find(img => img.is_primary)?.image_url || product.images[0]?.image_url
    const isOutOfStock = product.stock_quantity <= 0
    const price = product.discount_price ? parseFloat(product.discount_price) : parseFloat(product.base_price)

    const handleAddToCart = (e: React.MouseEvent) => {
        e.preventDefault()
        if (product.has_variants) {
            // In a robust implementation, this might open a quick-view modal.
            // Since we're navigating to the product page instead, we just let the link wrapping act,
            // or we could explicitly push here. We will just use the link in this setup.
            return
        }

        addItem({
            id: crypto.randomUUID(), // Temp ID for the cart item instance
            product_id: product.id,
            name: product.name,
            slug: product.slug,
            price: price.toString(),
            image_url: primaryImage || null,
            quantity: 1,
        })
        toast.success('Added to cart')
    }

    const toggleWishlist = (e: React.MouseEvent) => {
        e.preventDefault()
        setIsWishlisted(!isWishlisted)
        toast.success(isWishlisted ? 'Removed from wishlist' : 'Added to wishlist')
        // TODO: Tie to API
    }

    // Determine Discount %
    let discountPercent = 0
    if (product.discount_price && parseFloat(product.base_price) > parseFloat(product.discount_price)) {
        discountPercent = Math.round(((parseFloat(product.base_price) - parseFloat(product.discount_price)) / parseFloat(product.base_price)) * 100)
    }

    return (
        <Link href={`/products/${product.slug}`} className="group block">
            <Card className="rounded-2xl border-gray-100 shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden flex flex-col h-full bg-white relative">

                {/* Top Action Layer */}
                <div className="absolute top-3 left-3 right-3 flex justify-between items-start z-10 pointer-events-none">
                    {discountPercent > 0 ? (
                        <DiscountBadge percentage={discountPercent} />
                    ) : (
                        <div></div> // Spacer 
                    )}
                    <button
                        onClick={toggleWishlist}
                        className={cn(
                            "bg-white/80 backdrop-blur-sm p-2 rounded-full shadow-sm transition-colors pointer-events-auto",
                            isWishlisted ? "text-red-500" : "text-gray-400 hover:text-red-500"
                        )}
                    >
                        <Heart className="h-4 w-4" fill={isWishlisted ? 'currentColor' : 'none'} />
                    </button>
                </div>

                {/* Bottom Left Badge */}
                <div className="absolute top-[45%] lg:top-[50%] left-3 z-10 -translate-y-full">
                    {(product.stock_quantity > 0 && product.stock_quantity < 10) && (
                        <StockBadge quantity={product.stock_quantity} />
                    )}
                    {isOutOfStock && (
                        <Badge variant="secondary" className="bg-gray-800 text-white font-semibold text-[10px] px-2 py-0.5">Out of Stock</Badge>
                    )}
                </div>

                {/* Image Box */}
                <div className="relative aspect-[4/3] w-full overflow-hidden bg-gray-50 flex items-center justify-center shrink-0">
                    {primaryImage ? (
                        <Image
                            src={primaryImage}
                            alt={product.name}
                            fill
                            className="object-cover group-hover:scale-105 transition-transform duration-500"
                        />
                    ) : (
                        <div className="text-xl font-bold text-gray-300 tracking-wider">
                            {product.name.charAt(0)}
                        </div>
                    )}
                </div>

                {/* Content Box */}
                <div className="p-4 flex flex-col flex-1">
                    <p className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold mb-1">
                        {product.category_name}
                    </p>

                    <h3 className="font-semibold text-gray-900 line-clamp-2 text-sm leading-tight flex-1 group-hover:text-brand-primary transition-colors">
                        {product.name}
                    </h3>

                    <div className="mt-2 text-xs">
                        <StarRating rating={product.rating_avg} count={product.rating_count} />
                    </div>

                    <div className="mt-3 flex items-center gap-2">
                        <CurrencyDisplay
                            amount={price}
                            className="text-lg font-bold text-gray-900"
                        />
                        {product.discount_price && (
                            <>
                                <CurrencyDisplay
                                    amount={parseFloat(product.base_price)}
                                    className="text-sm text-gray-400 line-through"
                                />
                                <div className="ml-auto">
                                    <p className="text-xs text-gray-500 font-medium">Sale ends soon. Don&apos;t miss out!</p>
                                </div>
                            </>
                        )}
                    </div>

                    {/* Action Button */}
                    <div className="mt-4 shrink-0">
                        {isOutOfStock ? (
                            <Button className="w-full bg-gray-100 text-gray-400 hover:bg-gray-100 cursor-not-allowed" disabled>
                                Out of Stock
                            </Button>
                        ) : product.has_variants ? (
                            <Button
                                className="w-full bg-[#1A1A2E] hover:bg-[#2A2A4E] text-white"
                                onClick={(e) => {
                                    // Let default navigation happen
                                }}
                            >
                                Select Options
                            </Button>
                        ) : (
                            <Button
                                className="w-full bg-[#1A1A2E] hover:bg-[#2A2A4E] text-white gap-2 transition-transform active:scale-95"
                                onClick={handleAddToCart}
                            >
                                <ShoppingBag className="h-4 w-4" /> Add to Cart
                            </Button>
                        )}
                    </div>
                </div>
            </Card>
        </Link>
    )
}

export function ProductCardSkeleton() {
    return (
        <Card className="rounded-2xl border-gray-100 shadow-sm overflow-hidden flex flex-col h-full bg-white relative">
            <div className="aspect-[4/3] w-full bg-gray-100 animate-pulse"></div>
